// 全球能源项目世界地图 —— 2026-07 全球增量刷新批次
// 多代理分区×品类深度调研（发现→逐条 Web 事实核查），聚焦 2026 年（尤其 Q2/6-7 月）里程碑动态：
// 新公布 / FID / 开工 / 并网投运 / 重大规模或投资变化。含内联 descEn/detailEn（保持英文覆盖）。
// id 段 7400-7472（73 个）；concat 进 ENERGY_EXTRA；
// index.html 在 data-clients-mining.js 之后、progress.js 之前加载。
window.ENERGY_EXTRA = (window.ENERGY_EXTRA || []).concat([
  // ===== 东亚（7439-7466）=====
  {"id":7439,"name":"福建三峡全球首台20MW海上风电机组","en":"World's First 20 MW Offshore Wind Turbine (Fujian)","country":"中国","region":"东亚","cat":"renewable","coord":[119.8,25.4],"cap":"20MW（单机）","inv":0.5,"invText":"约$5000万（估，单机示范）","status":"投运","year":2026,"updated":"2026-02","owner":"中国三峡集团（金风科技供机）","flagship":false,"desc":"全球首台20MW海上风机，2026年2月并网发电，关键部件100%国产化","detail":"由中国三峡集团在福建海域安装、金风科技设计制造的全球首台单机容量20MW海上风电机组，2026年1月完成吊装，2月5日成功并网发电，是当前全球实际海洋环境中已并网单机容量最大的海上风机，实现全产业链自主可控与关键部件100%国产化。风轮直径300米，扫风面积超7万平方米（约10个足球场），搭载147米超长柔性叶片。设计年发电量超8000万千瓦时，可满足约4.4万户家庭一年用电，是继2023年16MW机组后我国海上风电重大装备的又一跨越。","descEn":"World's first 20 MW offshore wind turbine, grid-connected Feb 2026, 100% domestic key parts","detailEn":"Installed by China Three Gorges in waters off Fujian and designed and built by Goldwind, this is the world's first 20 MW offshore wind turbine and the largest single-unit offshore turbine grid-connected in a real marine environment, with 100% domestically produced key components. Lifted into place in January 2026, it began grid-connected generation on 5 February 2026. Its 300 m rotor sweeps over 70,000 m2 (about 10 football pitches) using 147 m flexible blades. Designed annual output exceeds 80 million kWh, enough for ~44,000 homes, following on from the 16 MW unit deployed off Fujian in 2023."},
  {"id":7440,"name":"中能建哈密1500MW光热+光伏多能互补示范","en":"CEEC Hami 1500MW PV-CSP Multi-Energy Demonstration","country":"中国","region":"东亚","cat":"renewable","coord":[93.5,43.6],"cap":"1.35GW 光伏 + 150MW 熔盐塔式光热（8h储热）","inv":9,"invText":"约$9亿（约¥65亿）","status":"在建","year":2026,"updated":"2026-04","owner":"中国能源建设集团（中能建）","flagship":false,"desc":"全球单期建设规模最大光储热一体化，2026年4月光伏区开工、冲刺年底并网","detail":"位于新疆哈密市巴里坤哈萨克自治县三塘湖镇东北约60公里岔哈泉区域，为中能建哈密“光（热）储”1500MW多能互补一体化绿电示范项目，总占地约5万亩、总投资约¥65亿元（约$9亿）。组合1.35GW光伏与150MW熔盐塔式光热，配套8小时高温熔盐储热、1座吸热塔及2座220kV升压汇集站，核心设备国产化率超99%。2026年4月光伏区正式开工，被称为全球单期建设规模最大的“光储热”一体化工程，整体进度已超八成，冲刺2026年底全容量并网。建成后年发电约30亿千瓦时，每年节约标煤约86.8万吨。","descEn":"World's largest single-phase PV-CSP-storage project; PV construction began April 2026, targeting end-2026 grid connection","detailEn":"Located about 60 km northeast of Santanghu Town, Barkol Kazakh Autonomous County, Hami, Xinjiang, the CEEC Hami 1,500 MW multi-energy complementary green-power demonstration spans ~50,000 mu with investment of about CNY 6.5 billion (~$900 million). It combines 1.35 GW of PV with 150 MW of molten-salt tower CSP backed by 8 hours of high-temperature molten-salt storage, one receiver tower and two 220 kV collector substations, with over 99% domestic core equipment. PV-zone construction started in April 2026; described as the world's largest single-phase PV-CSP-storage project, it is over 80% complete and targeting full grid connection by end-2026, with annual output of ~3 billion kWh saving ~868,000 tonnes of standard coal a year."},
  {"id":7441,"name":"两河口混合式抽水蓄能（4.2GW）","en":"Lianghekou Hybrid Pumped Storage Project (4.2GW)","country":"中国","region":"东亚","cat":"storage","coord":[101.05,30.55],"cap":"4.2GW（4×300MW抽蓄+3GW常规水电混合）","inv":30,"invText":"约$30亿（估）","status":"在建","year":2026,"updated":"2026-02","owner":"雅砻江流域水电开发有限公司","flagship":true,"desc":"全球在建最大混合式抽蓄，2026年2月地下厂房开挖完工双突破","detail":"位于四川雅砻江的两河口混合式抽水蓄能项目，是全球在建最大、海拔最高的混合式抽水蓄能工程，以两河口水库为上库、牙根一级水库为下库，新增4台单机300MW可逆机组，与已建3GW常规水电组合形成4.2GW调节能力。2026年2月22日达成地下厂房开挖完工与下库首仓混凝土浇筑“双突破”，标志由土建开挖转入机电安装。地下厂房埋深约500米、总长近200米、最大埋深650米。混合式设计使机组在丰枯、昼夜灵活切换，为西南电网与新能源大规模消纳提供长时调节，支撑2028年水风光储氢算示范区建设。","descEn":"World's largest hybrid pumped-storage under construction; twin milestones reached Feb 2026","detailEn":"On the Yalong River in Sichuan, the Lianghekou hybrid project is the world's largest and highest-altitude hybrid pumped-storage scheme under construction, using the Lianghekou reservoir as upper pool and the Yagen-1 reservoir as lower pool. It adds four 300 MW reversible units which, combined with 3 GW of existing conventional hydro, give 4.2 GW of regulating capacity. On 22 February 2026 it achieved twin breakthroughs, completing underground-powerhouse excavation and the first concrete pour of the lower reservoir, shifting from civil works to electromechanical installation. The powerhouse sits ~500 m underground, nearly 200 m long with a maximum depth of 650 m. The hybrid design lets units switch flexibly across seasons and day-night cycles for long-duration regulation of the southwest grid."},
  {"id":7447,"name":"藏东南-粤港澳大湾区 ±800kV 四端柔直特高压","en":"Southeast Tibet–Greater Bay Area ±800 kV Four-Terminal Flexible UHVDC","country":"中国","region":"东亚","cat":"grid","coord":[91.1,29.6],"cap":"±800kV四端柔性直流，10GW，2681km","inv":78,"invText":"约532亿元人民币(约78亿$)","status":"在建","year":2026,"updated":"2026-04","owner":"国家电网公司","flagship":true,"desc":"全球首个四端柔直特高压，西藏段2026年4月开工送粤","detail":"国家电网±800kV特高压'藏东南送粤港澳大湾区'工程，全球首个四端柔性直流(VSC)特高压，全长2681公里、跨西藏-云南-广西-广东，输送能力10GW，将藏东南清洁水风光电送往粤港澳大湾区。2026年1月广东段(博罗)开工，2026年4月西藏段(线路3标)正式开工。总投资约532亿元人民币，配套水风光一体化基地投资超1500亿元。计划2028年送电、2029年全面投运，年送电超43太瓦时，是世界海拔最高的特高压输电工程之一。","descEn":"World's first four-terminal flexible UHVDC; Tibet section broke ground April 2026","detailEn":"State Grid's ±800 kV UHV 'Southeast Tibet to Greater Bay Area' project — the world's first four-terminal flexible (VSC) UHVDC link, 2,681 km long across Tibet, Yunnan, Guangxi and Guangdong with 10 GW capacity, delivering southeast Tibet's clean hydro/wind/solar power to the Guangdong-Hong Kong-Macao Greater Bay Area. The Guangdong section (Boluo) broke ground in January 2026 and the Tibet line section formally started in April 2026. Total investment is about CNY53.2bn, with over CNY150bn of accompanying water-wind-solar base investment. Power transmission is slated for 2028 and full operation in 2029, delivering over 43 TWh/year — among the world's highest-altitude UHV links."},
  {"id":7450,"name":"中国太平岭核电4号机组（华龙一号）","en":"Taipingling Nuclear Unit 4 (Hualong One)","country":"中国","region":"东亚","cat":"nuclear","coord":[114.9833,22.6167],"cap":"约1100MWe（HPR1000 华龙一号压水堆）","inv":30,"invText":"约$30亿（估）","status":"在建","year":2026,"updated":"2026-05","owner":"中国广核集团（CGN）","flagship":false,"desc":"太平岭4号机组浇筑首罐核岛混凝土正式开工","detail":"位于中国广东省惠州市的太平岭核电站，规划6台华龙一号（HPR1000）机组、单台净装机约1100MW、总投资超1200亿元人民币。2026年5月10日中广核宣布4号机组浇筑首罐核安全相关混凝土，标志土建正式开工，是该厂址计划6台机组中的第4台（3号机组2025年6月开工）。华龙一号为中国自主三代压水堆，太平岭是粤港澳大湾区首个华龙一号核电项目，六台机组全部投运后年发电量将超550亿千瓦时。","descEn":"Taipingling Unit 4 pours first nuclear concrete, starting civil construction","detailEn":"At the Taipingling nuclear power station in Huizhou, Guangdong, China, six Hualong One (HPR1000) units are planned, each ~1,100 MW net, with total investment over CNY120 billion. On 10 May 2026 CGN poured first nuclear-safety-related concrete for Unit 4's reactor building, marking the official start of civil construction—the fourth of six planned units (Unit 3 began in June 2025). The HPR1000 is China's indigenous Gen-III PWR, and Taipingling is the first Hualong One project in the Greater Bay Area; once all six units operate, annual generation will exceed 55 billion kWh."},
  {"id":7466,"name":"高雄捷运红线南延（RLC02标）","en":"Kaohsiung MRT Red Line South Extension (RLC02)","country":"中国台湾","region":"东亚","cat":"transport","coord":[120.35,22.5],"cap":"小港—林园段，3.9公里双孔隧道，3座地下站+1座高架站","inv":9,"invText":"约9亿美元（NT$263.9亿）","status":"在建","year":2033,"updated":"2026-05","owner":"高雄捷运工程局 / Gamuda-上鼎营造联合体","flagship":false,"desc":"高雄捷运红线南延RLC02标2026年5月授出，Gamuda领衔","detail":"高雄市捷运工程局2026年5月将红线小港—林园段RLC02标土建与机电工程合同授予马来西亚Gamuda与本地上鼎营造组成的70:30联合体，合同金额约新台币263.9亿元（约9亿美元）。工程含3座地下站、1座高架站、3.9公里双孔隧道及6条横渡线，工期约7年4个月。这是Gamuda在台第10个项目，Gamuda应占份额约RM23.1亿。","descEn":"Kaohsiung MRT Red Line South Extension RLC02 awarded May 2026, led by Gamuda","detailEn":"In May 2026 Kaohsiung's MRT Bureau awarded the RLC02 civil-and-E&M contract for the Xiaogang–Linyuan (Red) Line to a 70:30 JV of Malaysia's Gamuda and local Shang Ting Construction, valued at about NT$26.39B (~$0.9B). Scope covers three underground stations, one elevated station, 3.9km of twin-bore tunnel and six cross passages, with completion in about 7 years 4 months — Gamuda's 10th Taiwan project (Gamuda's share ~RM2.31B)."},
  // ===== 东南亚（7424-7470）=====
  {"id":7424,"name":"道达尔-MK Land 库林光伏电站","en":"TotalEnergies & MK Land Kulim Solar Plant","country":"马来西亚","region":"东南亚","cat":"renewable","coord":[100.56,5.37],"cap":"30MWac(约50MWp)光伏","inv":0.37,"invText":"约1.45亿林吉特(约3700万美元)","status":"在建","year":2027,"updated":"2026-05","owner":"TotalEnergies / MK Land Holdings","flagship":false,"desc":"马来西亚绿电计划下光伏电站，2026年5月融资完成开工","detail":"位于马来西亚吉打州库林，道达尔能源(49%)与 MK Land 旗下 Solar Citra(51%)于 2026 年 5 月 13 日在企业绿电计划(CGPP)下对该 30MWac(约 50MWp)光伏电站达成融资完成并随即开工。项目占地约 115 英亩、约 8 万块组件，全部约 1.5TWh 年发电量将通过 21 年长期购电协议售予马来西亚主要科技与工业企业，计划 2027 年第三季度投运。约 1.45 亿林吉特(约 3700 万美元)项目融资由法国巴黎银行马来西亚担任独家安排行。","descEn":"Solar plant under Malaysia's green power programme, financial close and construction start May 2026","detailEn":"In Kulim, Kedah, Malaysia, TotalEnergies (49%) and MK Land's Solar Citra (51%) reached financial close and started construction on 13 May 2026 of a 30 MWac (about 50 MWp) solar plant under the Corporate Green Power Programme. Spanning about 115 acres with around 80,000 modules, its entire output of roughly 1.5 TWh will be sold under 21-year PPAs to major technology and industrial players, with operations targeted for Q3 2027. The roughly MYR145m (about US$37m) financing was arranged with BNP Paribas Malaysia as sole lender."},
  {"id":7425,"name":"农风电场(Nong Wind，老挝输越南)","en":"Nong Wind Power Project (Laos to Vietnam)","country":"老挝","region":"东南亚","cat":"renewable","coord":[106.6,16.55],"cap":"1200MW 风电(一期702MW+二期498MW)","inv":19,"invText":"约19亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"Chitchareune Construction","flagship":false,"desc":"老挝萨湾拿吉1.2GW跨境风电，特许权协议2026二季度签署","detail":"农风电场位于老挝萨湾拿吉农县，占地近 2.85 万公顷，由老挝 Chitchareune Construction 主导开发，旨在保障越南能源安全并满足老挝用电需求，总投资约 19 亿美元。特许权协议预计 2026 年第二季度签署。项目分两期开发，一期 702MW(约 11.23 亿美元)、二期 498MW(约 7.97 亿美元)，合计 1200MW，一期计划 2027 年底向越南送电、二期 2030 年投运。这是继 Monsoon、Savan 1 之后老越又一重要的跨境可再生能源合作工程。","descEn":"1.2GW cross-border wind in Savannakhet, Laos; concession contract expected Q2 2026","detailEn":"The Nong Wind Power Project in Nong district, Savannakhet, Laos, spans nearly 28,500 hectares and is led by Laos's Chitchareune Construction to support Vietnam's energy security and meet Laos's own demand, with total investment of about US$1.9bn. The concession contract is expected to be signed in Q2 2026. Developed in two phases (702 MW at ~US$1.12bn, then 498 MW at ~US$0.80bn, totalling 1,200 MW), phase one targets exporting power to Vietnam by end-2027 and phase two by 2030 - another major Laos-Vietnam cross-border renewable project after Monsoon and Savan 1."},
  {"id":7470,"name":"芹椰—头顿跨海桥隧","en":"Can Gio – Vung Tau Sea Crossing (Bridge & Tunnel)","country":"越南","region":"东南亚","cat":"transport","coord":[106.87,10.52],"cap":"全长约14.06公里：海上桥8010米+海底隧道3850米，6车道","inv":36,"invText":"约36亿美元（VND 93万亿）","status":"规划","year":2029,"updated":"2026-06","owner":"胡志明市 / Vingroup领衔投资联合体（BT/PPP）","flagship":false,"desc":"胡志明市跨海桥隧2026年获批，全长14公里连接芹椰与头顿","detail":"2026年，胡志明市以PPP-BT模式批准建设芹椰—头顿跨海大桥隧道方案，全长约14.06公里，其中海上桥8010米、海底隧道3850米（含3000米沉管），6车道。总投资约93万亿越南盾（约36亿美元），由Vingroup旗下芹椰城市旅游等企业组成的投资联合体提出，建设期2026—2029年，计划2026年7月前开工。建成后芹椰至头顿车程将从90—120分钟缩短至约10分钟，支撑芹椰新城与深水港开发。","descEn":"Ho Chi Minh City approves 14km Can Gio–Vung Tau sea bridge-tunnel, 2026","detailEn":"In 2026 Ho Chi Minh City approved, under a PPP-BT scheme, a Can Gio–Vung Tau sea crossing about 14.06km long — an 8,010m sea bridge plus a 3,850m undersea tunnel (including a 3,000m immersed section), with six lanes. Total investment is ~VND 93 trillion (~$3.6B), proposed by a Vingroup-led investor consortium including Can Gio Urban Tourism; construction runs 2026–2029 with a start targeted before July 2026. It will cut Can Gio–Vung Tau travel time from 90–120 minutes to about 10, underpinning the Can Gio new-city and deep-water port developments."},
  // ===== 南亚（7412-7446）=====
  {"id":7412,"name":"IndiGrid 180MW/360MWh 独立电网储能电站（古吉拉特 GETCO）","en":"IndiGrid–AmpereHour 180 MW/360 MWh Standalone BESS, GETCO Substation, Gujarat","country":"印度","region":"南亚","cat":"storage","coord":[72.6,22.3],"cap":"180MW/360MWh 电池储能","inv":1.5,"invText":"约$1.5亿（估，含IFC约$5500万债券）","status":"投运","year":2026,"updated":"2026-05","owner":"IndiGrid / AmpereHour Energy（购电方 GUVNL）","flagship":false,"desc":"印度最大独立电网侧储能之一，2026年5月全容量投运","detail":"位于印度古吉拉特邦GETCO 220kV变电站的180MW/360MWh独立电池储能电站，由IndiGrid联合AmpereHour Energy建设，业主/购电方为古吉拉特邦电力公司GUVNL，被普遍视为印度单点最大的公用事业级独立储能项目、亚洲最大储能之一。项目于2026年5月投运，从AmpereHour此前40MWh德里项目放大而来，覆盖从220kV并网到直流侧的整链优化以提升往返效率与可用电量，用于平抑风光波动、削峰填谷、减少弃风弃光并提升电网稳定。","descEn":"One of India's largest standalone grid BESS, fully commissioned May 2026","detailEn":"A 180 MW/360 MWh standalone battery storage plant at a GETCO 220 kV substation in Gujarat, India, built by IndiGrid with AmpereHour Energy for off-taker GUVNL—widely reported as India's largest single-site utility-scale BESS and among the largest in Asia. Commissioned in May 2026, it scaled up AmpereHour's earlier 40 MWh Delhi project with full electrical-chain optimization from the 220 kV grid connection down to the DC side to maximize round-trip efficiency and usable energy. It smooths solar/wind variability, provides peak shaving and cuts renewable curtailment."},
  {"id":7413,"name":"ACME Solar 300MW/1200MWh FDRE 保证峰值电力项目（拉贾斯坦 ISTS）","en":"ACME Solar 300 MW/1,200 MWh FDRE Assured-Peak Power Project, Rajasthan (ISTS)","country":"印度","region":"南亚","cat":"storage","coord":[73.31,27.5],"cap":"300MW + 1200MWh 储能（FDRE 可调度绿电，4小时峰值）","inv":3.5,"invText":"约$3.5亿（估）","status":"规划","year":2026,"updated":"2026-05","owner":"ACME Solar Holdings（购电方 SECI）","flagship":false,"desc":"ACME与SECI签25年FDRE可调度绿电PPA，2026年5月","detail":"ACME Solar于2026年5月26日通过子公司ACME Renewtech Sixth与印度太阳能公司SECI签署25年期购电协议，供应300MW/1200MWh的FDRE（可靠可调度可再生能源）保证峰值电力，属SECI FDRE第七批（2026年2月2日反向拍卖、2月10日中标函）。项目为跨州输电ISTS并网光储一体化，落地拉贾斯坦邦，电价6.28卢比/度，非光照时段提供4小时保证峰值电力、年最低可用率85%，计划2028年5月28日起供电；签约后ACME已签PPA组合升至约6570MW。","descEn":"ACME signs 25-year FDRE dispatchable-green-power PPA with SECI, May 2026","detailEn":"On May 26, 2026, ACME Solar (via subsidiary ACME Renewtech Sixth) signed a 25-year PPA with SECI to supply 300 MW/1,200 MWh of firm, dispatchable renewable energy (FDRE) assured-peak power under SECI's FDRE Tranche VII (e-reverse auction Feb 2, 2026; LOA Feb 10, 2026). The ISTS-connected solar-plus-storage project in Rajasthan is tariffed at ₹6.28/unit, provides four hours of assured peak power during non-solar hours with 85% minimum annual availability, and is scheduled to supply from May 28, 2028; ACME's signed-PPA portfolio rose to about 6,570 MW."},
  {"id":7414,"name":"Adani Green FY26 新增 5.05GW 可再生能源装机（卡夫达为主）","en":"Adani Green FY26 5.05 GW Renewable Capacity Addition (Khavda-led)","country":"印度","region":"南亚","cat":"renewable","coord":[71.2,23.8],"cap":"新增5051MW（光3409MW/风686MW/风光混合956MW）","inv":40,"invText":"约$40亿（估，FY26新增装机）","status":"投运","year":2026,"updated":"2026-04","owner":"Adani Green Energy","flagship":true,"desc":"Adani Green 2025-26财年新增超5GW，运营装机达19.3GW","detail":"Adani Green Energy在2025-26财年（截至2026年3月）新增5051MW可再生装机，为除中国外全球最大绿地年度扩张，运营组合达19.3GW，其中新增3409MW光伏、686MW风电、956MW风光混合。核心增量来自古吉拉特邦卡夫达（Khavda）超级园区——截至2026年4月该园区已建成约9.4GW，规划到2029年达30GW，是全球最大在建可再生能源园区；新增装机预计每年减碳约1000万吨。","descEn":"Adani Green added 5 GW+ in FY26, operating fleet reaches 19.3 GW","detailEn":"Adani Green added 5,051 MW of renewables in FY26 (to March 2026)—the largest greenfield annual expansion globally outside China—lifting its operating portfolio to 19.3 GW, comprising 3,409 MW solar, 686 MW wind and 956 MW wind-solar hybrid. Growth was led by the Khavda mega-park in Gujarat, which had reached about 9.4 GW by April 2026 en route to a planned 30 GW by 2029, the world's largest RE park under construction; the new capacity is expected to offset roughly 10 million tonnes of CO2 annually."},
  {"id":7415,"name":"孟加拉 523MW 光伏 PPA 组合（7 项目）","en":"Bangladesh 523 MW Solar PPA Portfolio (7 projects)","country":"孟加拉国","region":"南亚","cat":"renewable","coord":[90.4,23.7],"cap":"523MW 光伏（7个项目，10-200MW）","inv":4.5,"invText":"约$4.5亿（估）","status":"在建","year":2026,"updated":"2026-01","owner":"孟加拉电力发展局 BPDB","flagship":false,"desc":"孟加拉一次性签署7个光伏项目523MW购电协议","detail":"孟加拉电力发展局BPDB于2026年1月与7家开发商一次性签署总计523MW的光伏购电协议，单体规模10-200MW不等，分布于吉大港、博格拉、尼尔法马里、诺阿卡利等县，均进入建设阶段，每个项目将向国家电网供电20年。这是孟加拉在恢复此前被取消审批后、重启公用事业级光伏的标志性签约；据GlobalData预测该国光伏装机将于2035年达8.5GW。BPDB并规划在拉姆帕尔燃煤电厂旁建442MW全国最大光伏电站。","descEn":"Bangladesh signs 523 MW of solar PPAs across seven projects","detailEn":"In January 2026 Bangladesh's BPDB signed power purchase agreements totaling 523 MW across seven solar projects (10–200 MW each) in Chittagong, Bogra, Nilphamari and Noakhali districts, all entering construction and each supplying the national grid for 20 years. It is a landmark batch reviving utility-scale solar after previously cancelled approvals; GlobalData sees the country's PV reaching 8.5 GW by 2035. BPDB is also planning a 442 MW plant—its largest—beside the Rampal coal station."},
  {"id":7416,"name":"孟加拉 拉姆帕尔 442MW 光伏电站","en":"Bangladesh Rampal 442 MW Solar Plant","country":"孟加拉国","region":"南亚","cat":"renewable","coord":[89.55,22.6],"cap":"442MW 光伏","inv":2,"invText":"约$2亿","status":"规划","year":2026,"updated":"2026-04","owner":"孟加拉电力发展局 BPDB","flagship":false,"desc":"孟加拉规划全国最大442MW光伏，2026年4月披露","detail":"孟加拉电力发展局BPDB于2026年4月披露，将在1.32GW拉姆帕尔燃煤电厂旁（巴盖尔哈特县拉姆帕尔）开发442MW光伏电站，占地约685英亩，投资约2亿美元，建成后将成为孟加拉国最大光伏项目。项目自有资金约15%、其余85%来自政府电力发展基金；电价约0.050美元/度，低于Sonagazi等项目。项目利用燃煤电厂现有并网设施降低成本，若获批预计2030年12月建成，助力孟加拉2030年可再生占比20%目标。","descEn":"Bangladesh plans its largest 442 MW solar plant near Rampal coal station","detailEn":"In April 2026 Bangladesh's BPDB disclosed a 442 MW solar plant beside the 1.32 GW Rampal coal power station in Bagerhat, on about 685 acres for roughly $200m—set to be the country's largest solar installation. About 15% of the cost is self-funded and 85% from the government's Power Development Fund; electricity is priced near $0.050/kWh, below projects like Sonagazi. It leverages the coal plant's existing grid interconnection to cut costs and, if approved, targets completion by December 2030, supporting Bangladesh's 20%-renewables-by-2030 goal."},
  {"id":7417,"name":"Oracle Power 1.3GW 风光储混合项目（巴基斯坦 Jhimpir）","en":"Oracle Power 1.3 GW Wind-Solar-BESS Hybrid, Jhimpir, Pakistan","country":"巴基斯坦","region":"南亚","cat":"renewable","coord":[68,25],"cap":"1.3GW（800MW光伏 + 500MW风电 + 260MW BESS）","inv":12,"invText":"约$12亿（估）","status":"规划","year":2026,"updated":"2026-01","owner":"Oracle Power / CET（中国电力设备技术，国家电网子公司）","flagship":false,"desc":"Oracle与CET完成巴基斯坦Jhimpir 1.3GW风光储混合项目电网研究","detail":"英国上市开发商Oracle Power与合作方CET（中国电力设备技术，隶属国家电网）在巴基斯坦信德省Jhimpir推进1.3GW风光储混合项目，含800MW光伏、500MW风电及260MW电池储能（BESS）。2026年初，其合资Oracle Energy完成输电与并网接入研究：拟经35公里双回路输电线接入、净最大出力约1.1GW，配BESS与静止无功补偿以满足NTDC电网规范。项目投资约12亿美元，是巴基斯坦大型一体化可再生能源与储能项目之一，旨在缓解燃料供应波动。","descEn":"Oracle Power and CET complete grid study for Pakistan's 1.3 GW wind-solar-BESS hybrid","detailEn":"UK-listed Oracle Power and partner CET (China Electric Power Equipment and Technology, a State Grid subsidiary) are advancing a 1.3 GW wind-solar-BESS hybrid at Jhimpir, Sindh, Pakistan, comprising 800 MW solar, 500 MW wind and 260 MW of battery storage. In early 2026 its JV Oracle Energy completed a transmission and grid-interconnection study: a planned 35 km double-circuit line, roughly 1.1 GW net maximum output, with a BESS and static var compensator to meet the NTDC grid code. At roughly $1.2bn it is one of Pakistan's largest integrated renewables-plus-storage schemes, aimed at easing fuel-supply volatility."},
  {"id":7418,"name":"Enrich–NTPC 290MWh 独立电池储能项目（辛哈德里）","en":"Enrich–NTPC 290 MWh Standalone BESS, Simhadri, Andhra Pradesh","country":"印度","region":"南亚","cat":"storage","coord":[83,17.6],"cap":"290MWh 独立电池储能","inv":0.5,"invText":"约$5000万（估）","status":"规划","year":2026,"updated":"2026-04","owner":"Enrich Energy（购电方 NTPC）","flagship":false,"desc":"Enrich与NTPC签署290MWh独立储能合同，落地辛哈德里电厂","detail":"Enrich Energy于2026年4月与印度国家电力公司NTPC签署290MWh独立电池储能系统合同，项目落地安得拉邦辛哈德里（Simhadri）火电厂，通过2025年9月竞标获得，为Enrich首次进入储能领域。EPC范围涵盖电池、BMS、EMS、SCADA、PCS及变压器，并含远程监控与运维。项目是印度2026年储能爆发式增长的一部分——业内预计印度电网级电池储能将从2025年不足200MWh跃升至2026年底约5GWh，储能拉动因素来自光伏消纳与峰谷调节需求。","descEn":"Enrich signs 290 MWh standalone BESS contract with NTPC at Simhadri, April 2026","detailEn":"In April 2026 Enrich Energy signed a contract with India's NTPC for a 290 MWh standalone battery energy storage system at NTPC's Simhadri thermal power station in Andhra Pradesh, won via a September 2025 competitive bid and marking Enrich's entry into storage. The EPC scope covers batteries, BMS, EMS, SCADA, PCS and transformers plus remote monitoring and O&M. It is part of India's 2026 storage surge—grid-scale battery capacity is expected to jump from under 200 MWh in 2025 to roughly 5 GWh by end-2026, driven by solar integration and peak-shifting needs."},
  {"id":7419,"name":"孟加拉 77.6MW 光伏三电站招标（吉大港/兰加马蒂/迪纳杰布尔）","en":"Bangladesh 77.6 MW Three-Site Solar Tender","country":"孟加拉国","region":"南亚","cat":"renewable","coord":[91.9,22.5],"cap":"77.6MW 光伏（50/20/7.6MW）","inv":0.7,"invText":"约$7000万（估）","status":"规划","year":2026,"updated":"2026-04","owner":"孟加拉电力发展局 BPDB","flagship":false,"desc":"孟加拉2026年4月招标77.6MW三座光伏电站","detail":"孟加拉电力发展局BPDB于2026年4月24日为三座光伏电站发出招标，合计77.6MW（DC）：吉大港Rangunia 50MWp、迪纳杰布尔Baropukuria/Fulbari煤田用地20MWp、兰加马蒂Kaptai 7.6MWp。项目面向国际开发商、以交钥匙方式建设，资金来自BPDB自有及电力发展基金外汇资源，50MW电站要求中标后18个月内完工。这是孟加拉持续推进公用事业级光伏的又一批次，配合523MW大批签约与拉姆帕尔442MW规划，共同支撑其2035年8.5GW光伏目标。","descEn":"Bangladesh tenders three solar plants totaling 77.6 MW, April 2026","detailEn":"On April 24, 2026 Bangladesh's BPDB tendered three grid-connected solar plants totaling 77.6 MWp (DC)—50 MWp at Rangunia (Chittagong), 20 MWp on coal-field land at Baropukuria/Fulbari (Dinajpur) and 7.6 MWp at Kaptai (Rangamati). Open to international developers on a turnkey basis and funded from BPDB's own resources and the Power Sector Development Fund, the 50 MW plant must be completed within 18 months of award. It is another tranche in Bangladesh's utility-scale solar rollout, complementing the 523 MW PPA batch and the 442 MW Rampal plan toward 8.5 GW of PV by 2035."},
  {"id":7445,"name":"印度 Khavda-Nagpur ±800kV 6GW HVDC 输电","en":"Khavda–Nagpur ±800 kV 6 GW HVDC Link, India","country":"印度","region":"南亚","cat":"grid","coord":[71,23.9],"cap":"±800kV双极，6000MW，1200km","inv":30,"invText":"约2500亿卢比(约30亿$)","status":"在建","year":2026,"updated":"2026-01","owner":"印度国家电网公司(PGCIL) / BHEL / 日立能源印度","flagship":true,"desc":"印度首个TBCB竞标HVDC，2026年进入换流站设备建设期","detail":"从古吉拉特邦Khavda可再生能源园区KPS2换流站至马哈拉施特拉邦那格浦尔(Nagpur)的±800kV双极双向高压直流线，额定6000MW，全长1200公里，为印度500GW非化石能源目标的骨干输电通道。2024年11月由PGCIL在TBCB竞价中中标，成为印度首个TBCB框架下HVDC项目，BHEL联手日立能源印度承建KPS2与Nagpur两端±800kV/6000MW换流站(BHEL供应换流变、晶闸管阀等)及配套交流工程，造价约2500亿卢比。2025-26年项目进入设备制造与换流站建设阶段，计划2029年建成。","descEn":"India's first TBCB-awarded HVDC; in converter-build phase through 2026","detailEn":"A ±800 kV bipolar bidirectional HVDC line from the KPS2 station at Gujarat's Khavda renewable park to Nagpur in Maharashtra, rated 6,000 MW over 1,200 km — a backbone corridor for India's 500 GW non-fossil target. PGCIL won it via tariff-based competitive bidding in November 2024, India's first HVDC awarded under TBCB, with BHEL and Hitachi Energy India building the ±800 kV/6,000 MW converter terminals at KPS2 and Nagpur (BHEL supplying converter transformers, thyristor valves, etc.) plus associated AC works, costing around ₹250bn. Through 2025–26 the project entered equipment manufacturing and converter-station construction, targeting completion in 2029."},
  {"id":7446,"name":"印度 Bhadla-Fatehpur ±800kV 6GW HVDC 输电","en":"Bhadla–Fatehpur ±800 kV 6 GW HVDC Link, India","country":"印度","region":"南亚","cat":"grid","coord":[72.3,27.5],"cap":"±800kV双极，6000MW，950km","inv":30,"invText":"约2500亿卢比(约30亿$)","status":"在建","year":2026,"updated":"2026-02","owner":"阿达尼能源解决方案(AESL) / BHEL / 日立能源印度","flagship":true,"desc":"阿达尼史上最大订单，2026年2月获日资银团(MUFG/SMBC)绿色贷款","detail":"从拉贾斯坦邦Bhadla至北方邦Fatehpur的±800kV双极双向高压直流线，额定6000MW，走廊全长950公里，可为约6000万户家庭供电，服务印度500GW可再生能源目标。项目由阿达尼能源解决方案(AESL)子公司中标(约2500亿卢比，为AESL史上最大订单)，BHEL联合日立能源印度承建换流站。2026年2月AESL在其可持续债务框架下获得由MUFG银行与三井住友银行(SMBC)牵头的日本银团长期融资(符合赤道原则的绿色贷款)以推进该HVDC工程，预计2029年建成。","descEn":"Adani's largest-ever order; MUFG/SMBC green-loan financing secured Feb 2026","detailEn":"A ±800 kV bipolar bidirectional HVDC line from Bhadla in Rajasthan to Fatehpur in Uttar Pradesh, rated 6,000 MW over a 950 km corridor able to power roughly 60 million households, serving India's 500 GW renewable target. It was won by an Adani Energy Solutions (AESL) subsidiary (about ₹250bn, AESL's largest-ever order), with BHEL and Hitachi Energy India building the converters. In February 2026 AESL secured long-term financing from a Japanese bank consortium led by MUFG Bank and SMBC — a green loan under its sustainable-debt framework aligned with the Equator Principles — to advance the link, targeting completion in 2029."},
  // ===== 中东（7400-7472）=====
  {"id":7400,"name":"沙特第二批12GWh电池储能招标","en":"Saudi Arabia 12 GWh BESS Tender (Six Projects)","country":"沙特阿拉伯","region":"中东","cat":"storage","coord":[43.9,24.5],"cap":"3GW/12GWh 独立电池储能（6个项目，各500MW/2000MWh）","inv":30,"invText":"约$30亿（估，按$250/kWh）","status":"规划","year":2026,"updated":"2026-04","owner":"沙特电力采购公司(SPPC)","flagship":true,"desc":"沙特启动第二批3GW/12GWh独立电池储能项目资格预审","detail":"2026年4月，沙特电力采购公司(SPPC)启动第二批独立电池储能系统(BESS)项目招标，合计3GW/12GWh，六个项目各500MW/2000MWh（4小时储能），资格文件递交截止2026年5月5日。项目分布在卡西姆省(Samha)、麦加省(Al-Leeth、Khulis、Ashyrah)、麦地那省(Al-Henakiyah)及东部省(Sadawi)，采用BOO模式。SPPC已预审通过27家本地与国际企业。此举支撑沙特2030愿景48GWh储能目标。","descEn":"Saudi Arabia launches a second 3 GW/12 GWh batch of standalone BESS projects.","detailEn":"In April 2026 Saudi Power Procurement Company (SPPC) launched its second batch of standalone battery energy storage (BESS) projects totalling 3 GW/12 GWh, with six projects each rated 500 MW/2,000 MWh (4-hour storage) and statements of qualification due 5 May 2026. The projects span Qassim (Samha), Makkah (Al-Leeth, Khulis, Ashyrah), Madinah (Al-Henakiyah) and the Eastern Province (Sadawi), all under a build-own-operate model. SPPC prequalified 27 local and international firms. It supports Vision 2030's 48 GWh storage target."},
  {"id":7401,"name":"ZOE沙特首座大型电池储能工厂","en":"ZOE Energy Storage Saudi BESS Manufacturing Plant","country":"沙特阿拉伯","region":"中东","cat":"storage","coord":[46.85,24.55],"cap":"一期6GWh/年，扩至18GWh/年（150英亩）","inv":8,"invText":"约$8亿（估）","status":"规划","year":2027,"updated":"2026-05","owner":"ZOE储能（中资）与沙特本地伙伴合资","flagship":false,"desc":"中资ZOE与沙特伙伴合建王国首座大型电池储能制造基地","detail":"2026年5月，中国电池储能企业ZOE储能宣布与一家沙特本地企业成立合资公司，在沙特建设王国首座世界级大型电池储能(BESS)制造基地，为其继匈牙利之后第二个海外生产基地。150英亩厂区分两期建设：一期年产能6GWh，计划2027年第一季度投产；二期扩至18GWh。产品将获'沙特制造'认证并符合当地电网规范，供应海湾、中东、北非、中亚及非洲市场，厂内还设绿色能源学院。","descEn":"Chinese ZOE and a Saudi partner to build the Kingdom's first large-scale BESS factory.","detailEn":"In May 2026 Chinese battery-storage firm ZOE Energy Storage signed a joint venture with a local Saudi partner to build the Kingdom's first world-class large-scale BESS manufacturing base—its second overseas plant after Hungary. The 150-acre site is built in two phases: Phase I of 6 GWh/year starting production in Q1 2027, expanding to 18 GWh in Phase II. Products will carry 'Made in Saudi' certification and comply with local grid codes, supplying the Gulf, MENA, Central Asia and Africa, with an on-site Green Energy Academy."},
  {"id":7402,"name":"阿布扎比Khazna 1.5GW光伏电站","en":"Khazna 1.5 GW Solar PV IPP (Abu Dhabi)","country":"阿联酋","region":"中东","cat":"renewable","coord":[55.4,24.2],"cap":"1.5GW 光伏","inv":11,"invText":"约$11亿（融资约$11亿）","status":"在建","year":2028,"updated":"2026-01","owner":"马斯达尔(Masdar，60%) + 法国ENGIE(40%)","flagship":false,"desc":"马斯达尔与ENGIE的1.5GW Khazna光伏项目完成融资关闭","detail":"2026年1月，马斯达尔(Masdar，持股60%)与法国ENGIE(40%)宣布阿布扎比与艾因之间的1.5GW Khazna独立光伏项目(IPP)完成融资关闭。该项目2025年10月授标，与阿布扎比伊斯兰银行、法国农业信贷、KfW IPEX、法国巴黎银行、汇丰、三井住友信托及阿联酋开发银行等七家银行达成融资，并与阿联酋水电公司(EWEC)签署30年购电协议。项目计划2028年投入商运，年发电可供约16万户家庭用电，每年减碳约240万吨。","descEn":"Masdar and ENGIE reach financial close on the 1.5 GW Khazna solar PV project in Abu Dhabi.","detailEn":"In January 2026 Masdar (60%) and France's ENGIE (40%) announced financial close for the 1.5 GW Khazna solar PV IPP, located between Abu Dhabi and Al Ain. Awarded in October 2025, financing was secured with seven banks including Abu Dhabi Islamic Bank, Crédit Agricole CIB, KfW IPEX, BNP Paribas, HSBC, Sumitomo Mitsui Trust and Emirates Development Bank, under a 30-year PPA with EWEC. Scheduled to reach commercial operation in 2028, it will power about 160,000 homes and avoid roughly 2.4 million tonnes of CO2 a year."},
  {"id":7403,"name":"阿布扎比RTC全天候光储项目储能包","en":"Abu Dhabi RTC 19 GWh Storage (Sungrow 7.5 GWh Order)","country":"阿联酋","region":"中东","cat":"storage","coord":[54.4,23.6],"cap":"19GWh 储能（配5.2GW光伏）；阳光电源供货7.5GWh","inv":60,"invText":"约$60亿（AED220亿，全项目）","status":"在建","year":2027,"updated":"2026-05","owner":"马斯达尔(Masdar) + EWEC；阳光电源供储能","flagship":true,"desc":"阳光电源中标马斯达尔阿布扎比全天候项目7.5GWh储能供货","detail":"2026年5月21日，中国阳光电源(Sungrow)与马斯达尔在阿布扎比签约，为全球首个吉瓦级'全天候(RTC)'可再生能源项目供应7.5GWh的PowerTitan 3.0储能系统及2.6GW光伏逆变器。该RTC项目由马斯达尔与阿联酋水电公司(EWEC)开发，将5.2GW光伏与19GWh电池储能结合，实现全天候基荷绿电，总投资超220亿迪拉姆(约$60亿)，计划2027年投运。储能系统采用8小时充电、16小时放电优化循环，系统效率达99.3%。","descEn":"Sungrow wins Masdar's 7.5 GWh order for Abu Dhabi's world-first 24/7 solar-storage RTC project.","detailEn":"On 21 May 2026 China's Sungrow signed with Masdar in Abu Dhabi to supply 7.5 GWh of PowerTitan 3.0 storage plus 2.6 GW of PV inverters for the world's first gigascale round-the-clock (RTC) renewable project. Developed by Masdar and EWEC, the RTC scheme pairs 5.2 GW of solar with a 19 GWh BESS to deliver baseload green power. Total investment exceeds AED 22 billion (about $6bn); operation is targeted for 2027. The storage runs an 8-hour charge / 16-hour discharge cycle at up to 99.3% efficiency."},
  {"id":7443,"name":"沙特-埃及 3000MW HVDC 电力互联","en":"Saudi Arabia–Egypt 3,000 MW HVDC Interconnection","country":"沙特阿拉伯","region":"中东","cat":"grid","coord":[36.5,27.5],"cap":"±500kV HVDC，3000MW，含23km海缆+1300km架空线","inv":18,"invText":"约18亿美元","status":"在建","year":2026,"updated":"2026-04","owner":"沙特电力公司(SEC) / 埃及电力控股公司(EEHC) / 日立能源","flagship":false,"desc":"阿拉伯世界最大跨境电力互联，2026年分期投运","detail":"连接埃及Badr换流站与沙特麦地那East换流站、经Tabuk换流站跨越阿卡巴湾的±500kV高压直流工程，含约23公里海底电缆与1300公里架空线(沙特965km、埃及335km)，设计输送3000MW，是中东首个大型HVDC互联，总投资约18亿美元。2025年底工程完工度达约95%，Pole I(1500MW双向)于2025年末至2026年初调试。2026年埃及总理Madbouly视察Badr换流站，确认目标2026年4月投运，届时成为阿拉伯世界最大跨境电力通道。日立能源提供HVDC核心技术。","descEn":"Arab world's largest cross-border power link, phased commissioning 2026","detailEn":"A ±500 kV HVDC link connecting Egypt's Badr converter station with Saudi Arabia's Madinah East station via a Tabuk converter across the Gulf of Aqaba, comprising about 23 km of submarine cable and 1,300 km of overhead lines (965 km in Saudi Arabia, 335 km in Egypt), rated 3,000 MW — the Middle East's first large-scale HVDC interconnection, costing about $1.8 billion. It reached roughly 95% completion by end-2025, with Pole I (1,500 MW bidirectional) commissioning in early 2026. In 2026 Egypt's PM confirmed an April 2026 go-live target, making it the largest cross-border power link in the Arab world. Hitachi Energy supplies the HVDC technology."},
  {"id":7453,"name":"拉斯拉凡石化联合体（乙烷裂解）","en":"Ras Laffan Petrochemical Complex","country":"卡塔尔","region":"中东","cat":"petro","coord":[51.55,25.88],"cap":"乙烯 210万吨/年（中东最大乙烷裂解）","inv":60,"invText":"约$60亿","status":"在建","year":2026,"updated":"2026-04","owner":"QatarEnergy(70%) / Chevron Phillips Chemical(30%)","flagship":false,"desc":"中东最大乙烷裂解装置预计2026年底建成投产","detail":"位于卡塔尔拉斯拉凡工业城的石化联合体由QatarEnergy持股70%、雪佛龙菲利普斯化学(CPChem)持股30%，总投资约60亿美元，建有中东规模最大的乙烷裂解装置，乙烯年产能210万吨，配套两条聚乙烯生产线。2022年6月现场早期工程动工，预计2026年底建成投产，是卡塔尔在扩张LNG产能同时纵深发展石化产业链的核心工程。","descEn":"Middle East's largest ethane cracker set for late-2026 commissioning","detailEn":"The Ras Laffan petrochemical complex in Qatar, owned 70% by QatarEnergy and 30% by Chevron Phillips Chemical (CPChem), carries a ~$6 billion investment and houses the largest ethane cracker in the Middle East at 2.1 million tonnes/year of ethylene plus two polyethylene trains. Early site works began in June 2022 and commissioning is expected by late 2026 as Qatar deepens its petrochemical chain alongside its LNG capacity expansion."},
  {"id":7454,"name":"亚喀巴绿氨出口枢纽（Jordan Green Ammonia）","en":"Aqaba Green Ammonia Export Hub","country":"约旦","region":"中东","cat":"petro","coord":[35.02,29.53],"cap":"绿氨 约10万吨/年 + 550MW光伏/储能","inv":10,"invText":"约$10亿","status":"规划","year":2030,"updated":"2026-05","owner":"Jordan Green Ammonia（Hynfra/Fidelity）","flagship":false,"desc":"约旦批准首个10亿美元绿氨出口项目","detail":"2026年5月约旦内阁批准能源与矿产资源部与Jordan Green Ammonia公司（波兰Hynfra与阿联酋Fidelity Group组成的合资体）签署的亚喀巴绿氢绿氨项目，投资约10亿美元，用地逾1000公顷，毗邻亚喀巴港。项目配套专用550MW光伏与电池储能离网运行，通过电解水制氢生产绿氨，年产能约10万吨，面向欧洲和亚洲出口。财务关闭预计2027年9月，2030年11月投产，为约旦首个绿氨出口枢纽。","descEn":"Jordan approves its first $1B green ammonia export project","detailEn":"In May 2026 Jordan's cabinet approved an agreement between the Ministry of Energy and Mineral Resources and Jordan Green Ammonia Co. (a Polish-Emirati consortium of Hynfra and Fidelity Group) for a green hydrogen/ammonia project in Aqaba, investing ~$1 billion over 1,000+ hectares adjacent to the Port of Aqaba. It pairs a dedicated 550 MW solar plant with battery storage in an off-grid setup to produce ~100,000 t/year of green ammonia via water electrolysis for European and Asian export. Financial close is expected in September 2027 and operations in November 2030."},
  {"id":7471,"name":"中国能建阿布扎比特维拉C 2600MW燃气联合循环电站","en":"Energy China Abu Dhabi Taweelah C 2600MW CCGT Power Plant","country":"阿联酋","region":"中东","cat":"petro","coord":[54.75,24.75],"cap":"净出力 2600MW 双燃料燃气联合循环","inv":16.87,"invText":"$16.87亿（约114.2亿元人民币）","status":"在建","year":2026,"updated":"2026-06","owner":"中国能建","flagship":false,"desc":"中国能建签约阿布扎比特维拉C 2600MW燃气电站EPC，$16.87亿","detail":"2026年，中国能建联营体（中能建国际、广东火电、广东院）签署阿联酋阿布扎比特维拉C（Taweelah C）燃气联合循环电站EPC总承包合同，金额16.87亿美元（约114.2亿元人民币）。项目建设净出力2600MW双燃料燃气联合循环电站，总工期32个月，所发电力由阿联酋水电公司EWEC全额收购；项目公司由沙特ACWA Power（阿尔朱美亚能源水务）与新加坡胜科等组成，西门子能源供应3台燃气轮机、2台汽轮机及发电机。这是中国能建在海湾大型气电EPC市场的重要突破。","descEn":"Energy China signs EPC for Abu Dhabi Taweelah C 2600MW CCGT plant, USD 1.687bn","detailEn":"In 2026 an Energy China consortium (CEEC International, Guangdong Thermal Power, Guangdong EPDI) signed the EPC contract for the Taweelah C combined-cycle gas plant in Abu Dhabi for USD 1.687bn (about RMB 11.42bn). The plant delivers 2,600MW net of dual-fuel CCGT capacity on a 32-month schedule, with all output offtaken by EWEC. The project company is led by Saudi ACWA Power and Singapore's Sembcorp, with Siemens Energy supplying three gas turbines, two steam turbines and the generators. It marks a major Energy China win in the Gulf's large gas-power EPC market."},
  {"id":7472,"name":"中国能建山西院阿曼Dhofar II 125MW风电项目","en":"Energy China Oman Dhofar II 125MW Wind Project","country":"阿曼","region":"中东","cat":"renewable","coord":[54,17.6],"cap":"125MW 风电 + 400kV 升压站","inv":1.8,"invText":"约$1.8亿（估）","status":"在建","year":2026,"updated":"2026-02","owner":"中国能建","flagship":false,"desc":"中国能建山西院签约阿曼佐法尔II 125MW风电EPC，年发电约3.97亿度","detail":"2026年2月，中国能建山西院（经其阿曼子公司中标）与新加坡胜科工业在上海签署阿曼DhofarⅡ 125兆瓦风电项目EPC合同。项目位于阿曼佐法尔省，装机125MW，配套新建1座400kV升压站及约3.7公里外送线路，涵盖风电场设计、设备采购、施工、调试及后期服务。建成后年发电约3.97亿千瓦时，将提升阿曼绿电占比、优化能源结构。这是山西院在阿曼开发的第四个总承包项目，进一步巩固其在阿曼新能源市场的地位。","descEn":"Energy China's Shanxi institute signs Oman Dhofar II 125MW wind EPC, ~397 GWh/yr","detailEn":"In February 2026 Energy China's Shanxi institute (via its Omani subsidiary, which won the bid) signed in Shanghai the EPC contract with Singapore's Sembcorp for the Dhofar II 125MW wind project in Oman. Located in Dhofar Governorate, it pairs 125MW of wind capacity with a new 400kV substation and about 3.7km of evacuation line, covering wind-farm design, procurement, construction, commissioning and after-service. Once operating it will generate about 397 million kWh a year, raising Oman's green-power share. It is the institute's fourth EPC project in Oman, reinforcing its position in the Omani renewables market."},
  // ===== 欧洲（7426-7467）=====
  {"id":7426,"name":"RWE 诺福克先锋东+西海上风电","en":"RWE Norfolk Vanguard East & West Offshore Wind Farms","country":"英国","region":"欧洲","cat":"renewable","coord":[2.3,53.2],"cap":"2.76GW 海上风电（2×1.38GW，Vestas V236-15MW）","inv":90,"invText":"约$90亿（估）","status":"规划","year":2030,"updated":"2026-03","owner":"RWE / KKR（各50%）","flagship":true,"desc":"英国2.76GW海上风电，2026年3月锁定Vestas机组，夏季FID","detail":"位于英国诺福克海岸以东约45公里以上的东安格利亚海域，先锋东与先锋西两座风场各1.38GW、合计2.76GW，可为约300万英国家庭供电。两场在2026年1月CfD第七轮(AR7)中标，RWE与KKR达成长期合作、KKR购入各50%股权。2026年2月RWE向Vestas订购先锋西1.38GW机组、3月再签先锋东1.38GW（92台V236-15MW）供货协议，合计2.76GW。合作交割、项目融资及最终投资决定(FID)目标2026年夏季，两场分别计划2029、2030年投运。","descEn":"UK 2.76GW offshore wind; Vestas turbine orders signed Feb–Mar 2026, FID due summer","detailEn":"In the East Anglia zone more than 45 km off the Norfolk coast, Vanguard East and West are each 1.38GW (2.76GW total), enough for ~3 million UK homes. Both won CfDs in the January 2026 Allocation Round 7 (AR7), with KKR taking a 50% stake alongside RWE. In February 2026 RWE ordered 1.38GW of Vestas turbines for Vanguard West and in March 2026 a further 1.38GW (92 V236-15MW units) for Vanguard East, totalling 2.76GW. Partnership close, financing and FID are targeted for summer 2026, with commissioning in 2029 and 2030."},
  {"id":7427,"name":"ENGIE 安达卢西亚 Álora+Tarifa 储能","en":"ENGIE Álora & Tarifa BESS (Andalusia)","country":"西班牙","region":"欧洲","cat":"storage","coord":[-5.6,36.5],"cap":"278MW / 1.1GWh 电池储能（4小时）","inv":4,"invText":"约$4亿（估）","status":"规划","year":2028,"updated":"2026-04","owner":"ENGIE（法国，购自Rolwind Renovables）","flagship":false,"desc":"西班牙在建最大储能，2026年4月收购，配同步调相机","detail":"位于西班牙安达卢西亚，由Álora（78MW/312MWh）与Tarifa（200MW/800MWh）两座4小时储能电站组成，合计278MW/1.1GWh，是西班牙当前开发中规模最大的电池储能项目。2026年4月ENGIE从西班牙开发商Rolwind Renovables手中完成收购，两站均配置同步调相机以提供惯量与无功、稳定电网。工程计划2027年开工、2028年内陆续投运；ENGIE欧洲储能组合借此突破1GW，覆盖八国。","descEn":"Spain's largest BESS under development; acquired by ENGIE Apr 2026, with synchronous condensers","detailEn":"In Andalusia, Spain, the pair of 4-hour storage sites at Álora (78MW/312MWh) and Tarifa (200MW/800MWh) total 278MW/1.1GWh, the largest BESS under development in the country. ENGIE completed the acquisition from Spanish developer Rolwind Renovables in April 2026; both sites use synchronous condensers for inertia and reactive-power grid support. Construction is planned for 2027 with commissioning across 2028, pushing ENGIE's European storage fleet past 1GW across eight countries."},
  {"id":7428,"name":"Lightsource bp Valle 3&4 光伏","en":"Lightsource bp Valle 3 & 4 Solar Cluster","country":"西班牙","region":"欧洲","cat":"renewable","coord":[-4.85,41.72],"cap":"330MWp 光伏（含农光互补试点）","inv":2.5,"invText":"约$2.5亿（估）","status":"在建","year":2027,"updated":"2026-01","owner":"Lightsource bp（bp旗下）","flagship":false,"desc":"西班牙巴利亚多利德330MWp光伏，2025年底破土动工","detail":"位于西班牙卡斯蒂利亚-莱昂大区巴利亚多利德省Wamba镇的Valle 3与Valle 4联建光伏集群，规模330MWp。Lightsource bp已破土动工，计划2027年投运，带动Wamba、Ciguñuela、Zaratán及巴利亚多利德等周边村镇经济，施工期创造约450个岗位。项目内设农光互补(agriPV)试点，改良小麦、燕麦、大豆、黑麦等作物管理，并获UNEF可持续卓越印章。是Lightsource bp西班牙约2.5GW组合的一部分。","descEn":"330MWp solar cluster in Valladolid, Spain; ground broken late 2025","detailEn":"The co-located Valle 3 and Valle 4 solar cluster in Wamba, Valladolid province (Castilla y León), Spain, totals 330MWp. Lightsource bp has broken ground with operation targeted for 2027, supporting nearby villages including Wamba, Ciguñuela and Zaratán and creating around 450 construction jobs. It hosts an agrivoltaic (agriPV) pilot to improve management of crops such as wheat, oats, soybeans and rye and holds UNEF's sustainability excellence seal. It is part of Lightsource bp's ~2.5GW Spanish portfolio."},
  {"id":7429,"name":"European Energy 维齐尼农光互补","en":"European Energy Vizzini AgriPV Plant","country":"意大利","region":"欧洲","cat":"renewable","coord":[14.75,37.16],"cap":"225.5MW 农光互补光伏（约405GWh/年）","inv":2.2,"invText":"超€2亿（约$2.2亿）","status":"在建","year":2027,"updated":"2026-05","owner":"European Energy（丹麦）","flagship":false,"desc":"意大利最大农光互补光伏，2026年5月西西里开工","detail":"位于意大利西西里岛维齐尼(Vizzini)附近、占地约260公顷的225.5MW农光互补(agrivoltaic)光伏项目，是意大利最大的同类项目、也是欧洲最大之一。2025年12月European Energy作出超€2亿的最终投资决定(FID)，2026年5月正式开工。项目将光伏与农牧结合——组件距地1.3米、约820只绵羊放牧，另划90公顷造林、25公顷种植橄榄与仙人掌等缓解措施；预计年发电约405GWh，可供逾13.5万户，计划2027年底投运。","descEn":"Italy's largest agrivoltaic solar plant; construction started in Sicily May 2026","detailEn":"Near Vizzini in Sicily, Italy, this 225.5MW agrivoltaic (agriPV) project spans about 260 hectares and is Italy's largest of its kind and one of Europe's largest. European Energy took a final investment decision exceeding €200 million in December 2025 and started construction in May 2026. It combines solar with farming—modules 1.3m above ground with ~820 grazing sheep, plus 90 ha of reforestation and 25 ha of mitigation planting (olive and prickly pear). Expected to generate ~405GWh/year for over 135,000 households, targeting operation by end-2027."},
  {"id":7430,"name":"Enerjisa Uygar 风电场","en":"Enerjisa Üretim Uygar Wind Farm","country":"土耳其","region":"欧洲","cat":"renewable","coord":[27.2,38.5],"cap":"250MW 陆上风电（60台机组，约1TWh/年）","inv":3,"invText":"约$3亿（估）","status":"在建","year":2026,"updated":"2026-05","owner":"Enerjisa Üretim（E.ON与Sabancı合资）","flagship":false,"desc":"土耳其伊兹密尔250MW风电，YEKA-2项目，2026年首期投产","detail":"Uygar风电场是Enerjisa Üretim（德国E.ON与土耳其Sabancı合资）的第30座电厂，属YEKA-2招标项目，位于土耳其西部伊兹密尔(İzmir)省，规划总装机250MW、60台机组，年发电约1TWh。公司计划在2026年一季度前完成YEKA-2各风场，Uygar首批机组于2026年上半年投产发电。该时段土耳其多个大型风电项目集中投运，推动全国装机与风电占比持续提升。","descEn":"250MW wind farm in İzmir, Turkey (YEKA-2); first units commissioned in 2026","detailEn":"The Uygar wind farm is Enerjisa Üretim's (a JV of Germany's E.ON and Turkey's Sabancı) 30th power plant and a YEKA-2 auction project, located in İzmir province, western Turkey, planned at 250MW across 60 turbines generating about 1TWh a year. The company aimed to complete its YEKA-2 farms by Q1 2026, with Uygar's first units starting generation in the first half of 2026, part of a wave of large Turkish wind commissionings lifting national capacity and wind's share."},
  {"id":7431,"name":"ENGIE Drogenbos 电池储能","en":"ENGIE Drogenbos BESS (Brussels)","country":"比利时","region":"欧洲","cat":"storage","coord":[4.31,50.79],"cap":"80MW / 320MWh 电池储能（4小时，88个电池集装箱）","inv":1.2,"invText":"约$1.2亿（估）","status":"在建","year":2027,"updated":"2026-05","owner":"ENGIE / NHOA Energy","flagship":false,"desc":"布鲁塞尔近郊Drogenbos电厂320MWh储能，2026年5月开工","detail":"ENGIE与NHOA Energy在布鲁塞尔以南不足10公里的Drogenbos燃气电厂厂区建设一座80MW/320MWh（4小时、88个电池集装箱）电池储能系统，2026年5月举行奠基（施工自2026年3月起），计划2027年9月完工。项目在比利时第五轮容量补偿机制(CRM)拍卖中中标，获2027年11月起15年协议。NHOA负责供货、调试与长期运维；这是ENGIE在比利时的第三大储能项目，使其比利时储能规模接近400MW，欧洲储能组合突破1GW。","descEn":"320MWh BESS at ENGIE's Drogenbos gas plant near Brussels; ground broken May 2026","detailEn":"ENGIE and NHOA Energy are building an 80MW/320MWh (4-hour, 88 battery containers) storage system at ENGIE's Drogenbos gas station less than 10 km south of Brussels, Belgium, with groundbreaking in May 2026 (construction from March 2026) and completion due September 2027. It won Belgium's fifth Capacity Remuneration Mechanism (CRM) auction with a 15-year contract from November 2027. NHOA supplies, commissions and services the project; ENGIE's third-largest Belgian BESS, it lifts the group's Belgian storage toward 400MW and its European fleet past 1GW."},
  {"id":7444,"name":"东部绿色联络线4 (EGL4) 英国 HVDC 海缆","en":"Eastern Green Link 4 (EGL4) HVDC Subsea Cable, UK","country":"英国","region":"欧洲","cat":"grid","coord":[-2,55.5],"cap":"2GW HVDC，法夫-诺福克，约530km海缆(总电缆超640km)","inv":40,"invText":"约30亿英镑(约40亿$)","status":"在建","year":2026,"updated":"2026-03","owner":"SSEN Transmission / SP Energy Networks / National Grid","flagship":true,"desc":"苏格兰-英格兰第四条HVDC超级高速路，2026年3月签30亿英镑供应链合同","detail":"连接苏格兰法夫(Fife)与英格兰诺福克(Norfolk)的2GW高压直流海底联络线，约530公里海缆可为约150万户英国家庭供电，将苏格兰海上风电输往英格兰负荷中心。2026年2月Prysmian获得约20亿英镑电缆供应合同(供应超640公里HVDC电缆)，2026年3月西门子能源获得约30亿英镑换流站合同(法夫与诺福克各一座)，累计签署约30亿英镑供应链合同，成为项目重大里程碑。主体施工计划2028年启动、2033年建成，是英国东海岸多条HVDC电力超级高速路之一。","descEn":"Scotland-England's 4th HVDC superhighway; £3bn supply contracts signed March 2026","detailEn":"A 2 GW HVDC subsea link connecting Fife in Scotland with Norfolk in England, whose ~530 km cable can power about 1.5 million UK homes, moving Scottish offshore wind to English demand centers. In February 2026 Prysmian won a roughly £2bn cable supply contract (over 640 km of HVDC cable), and in March 2026 Siemens Energy secured the ~£3bn converter-station contract (one each in Fife and Norfolk), taking signed supply-chain deals to about £3bn — a major project milestone. Main construction is planned for 2028 and completion in 2033, part of the UK east-coast fleet of HVDC electricity superhighways."},
  {"id":7448,"name":"希腊-塞浦路斯 大海联络线 (GSI) HVDC 海缆","en":"Great Sea Interconnector (GSI) HVDC Cable, Greece–Cyprus","country":"希腊","region":"欧洲","cat":"grid","coord":[25,35],"cap":"HVDC海缆总长约1208km(希-塞段898km)，约2000MW","inv":20,"invText":"希-塞段合同约14.3亿欧元(约20亿$)","status":"规划","year":2026,"updated":"2026-04","owner":"IPTO(希腊输电网) / Nexans","flagship":false,"desc":"希腊-塞浦路斯-以色列联网，2026年因付款争议受阻、转向EIB求援","detail":"连接希腊、塞浦路斯与以色列电网的HVDC海底联络线，塞浦路斯至希腊段898公里、以色列至塞浦路斯段310公里，总长约1208公里，总输送约2000MW，Nexans承担希-塞段(2023年7月签约、合同约14.3亿欧元，创纪录)，获欧盟CEF约6.57亿欧元资助。2025年3月因IPTO冻结对Nexans付款、且塞浦路斯迟迟未批首笔约2500万欧元年度出资而暂停，土耳其军舰曾阻挠海底勘测。2026年4月21日希腊与塞浦路斯联名致函欧洲投资银行(EIB)请求融资以重启项目，但前景仍存重大不确定性，完工推迟至2028-29年后。","descEn":"Greece-Cyprus-Israel link; 2026 payment disputes, EIB financing sought","detailEn":"An HVDC subsea interconnector linking the Greek, Cypriot and Israeli grids — 898 km from Cyprus to Greece and 310 km from Israel to Cyprus, about 1,208 km total and roughly 2,000 MW, with Nexans building the Greece–Cyprus section (signed July 2023, a record ~€1.43bn contract) and €657m of EU CEF funding. It was paused in March 2025 when IPTO froze payments to Nexans and Cyprus stalled on approving the first ~€25m annual contribution, while Turkish warships had earlier obstructed seabed surveys. On 21 April 2026 Greece and Cyprus jointly wrote to the European Investment Bank requesting financing to restart the project, but its future remains highly uncertain with completion pushed beyond 2028-29."},
  {"id":7465,"name":"都柏林 MetroLink 地铁线","en":"Dublin MetroLink","country":"爱尔兰","region":"欧洲","cat":"transport","coord":[-6.26,53.35],"cap":"18.8公里全自动地铁，16座车站，经都柏林机场","inv":103,"invText":"约103亿美元（€9.5B商业论证）","status":"规划","year":2035,"updated":"2026-06","owner":"爱尔兰交通基础设施局（TII）","flagship":true,"desc":"都柏林首条地铁获批，2026年启动招标与前期工程","detail":"MetroLink为都柏林首条地铁，全长18.8公里、设16座车站，从北郊Swords经都柏林机场至南部Charlemont，全自动运行。内阁批准约95亿欧元商业论证后，项目2026年从规划进入采购阶段：2026年2月启动约79亿欧元土建合同招标，5月启动M500铁路系统合同采购，前期工程（含机场站体）同步展开。TII为业主，是爱尔兰史上最大公共交通项目。","descEn":"Dublin's first metro approved; procurement and enabling works begin 2026","detailEn":"MetroLink is Dublin's first metro, an 18.8km fully automated line with 16 stations running from northern suburb Swords through Dublin Airport to Charlemont. After cabinet approved its ~€9.5B business case, the project moved from planning to procurement in 2026: bidding for the ~€7.9B civil contracts opened in Feb 2026 and the M500 rail-systems procurement launched in May 2026, with enabling works (including the airport station box) proceeding in parallel. Owned by Transport Infrastructure Ireland, it is Ireland's largest public-transport project."},
  {"id":7467,"name":"那不勒斯地铁10号线","en":"Naples Metro Line 10","country":"意大利","region":"欧洲","cat":"transport","coord":[14.31,40.92],"cap":"首段6.5公里全自动地铁，3座车站，7列3节无人驾驶列车","inv":7,"invText":"约7亿美元（基础€238M，含选项可达€630M）","status":"在建","year":2032,"updated":"2026-05","owner":"EAV / CAF 领衔联合体","flagship":false,"desc":"那不勒斯首条全自动地铁10号线2026年5月签约，CAF领衔","detail":"2026年5月4日，区域运营商EAV与CAF领衔联合体签署那不勒斯地铁10号线系统与车辆合同，基础金额约2.38亿欧元，含全部选项可超6.3亿欧元（约7亿美元）。联合体含CAF、AET、Ventura、MerMec STE与Leonardo。首段6.5公里连接Afragola Centro与1号线Piazza Di Vittorio，设3座车站，供应CAF Optio CBTC（GoA4全自动）信号、7列3节无人驾驶列车及电气化、站台屏蔽门等，是该市首条全自动地铁。","descEn":"Naples' first fully automated metro Line 10 signed May 2026, led by CAF","detailEn":"On 4 May 2026 regional operator EAV signed a contract with a CAF-led consortium for the systems and rolling stock of Naples Metro Line 10, a base value of ~€238M rising above €630M (~$0.7B) with all options; the consortium includes CAF, AET, Ventura, MerMec STE and Leonardo. The first 6.5km section links Afragola Centro to Line 1 at Piazza Di Vittorio with three stations, supplying CAF's Optio CBTC (GoA4) automation, seven three-car driverless trainsets, electrification and platform screen doors — the city's first fully automated metro."},
  // ===== 北美（7432-7469）=====
  {"id":7432,"name":"威奇托光伏电站（谷歌数据中心PPA）","en":"Wichita Solar Farm (Google PPA)","country":"美国","region":"北美","cat":"renewable","coord":[-97.5,33.3],"cap":"805 MWp 光伏","inv":8,"invText":"约$8亿（估）","status":"在建","year":2026,"updated":"2026-02","owner":"TotalEnergies（道达尔能源）","flagship":false,"desc":"道达尔为谷歌得州数据中心供电的805MW光伏，2026Q2开工","detail":"位于美国得克萨斯州达拉斯以西的805MWp光伏电站，由道达尔能源自持开发。2026年2月道达尔与谷歌签署两份15年期购电协议，合计1GW（威奇托805MWp+Mustang Creek 195MWp），15年内供应约28TWh绿电给谷歌得州AI数据中心，为道达尔在美国签下的最大PPA。威奇托项目定于2026年第二季度开工，建设期将创造数百个岗位并带来可观地方税收。","descEn":"TotalEnergies' 805 MW Texas solar farm powering Google data centers, breaking ground Q2 2026","detailEn":"An 805 MWp solar farm west of Dallas, Texas, owned and developed by TotalEnergies. In February 2026 TotalEnergies signed two 15-year PPAs with Google totaling 1 GW (Wichita 805 MWp + Mustang Creek 195 MWp), delivering ~28 TWh of green power over 15 years to Google's Texas AI data centers — the largest renewable PPA volume TotalEnergies has ever signed in the US. Wichita construction is scheduled to start in Q2 2026, creating several hundred jobs."},
  {"id":7433,"name":"格林河能源中心（光储一体）","en":"Green River Energy Center","country":"美国","region":"北美","cat":"storage","coord":[-110.15,39],"cap":"400 MW 光伏 + 400MW/1600MWh 储能","inv":10,"invText":"逾$10亿","status":"投运","year":2026,"updated":"2026-06","owner":"rPlus Energies","flagship":false,"desc":"犹他州最大光储项目，400MW光伏+1.6GWh储能，2026年6月投运","detail":"位于美国犹他州埃默里县的格林河能源中心，配置400MW光伏与400MW/1600MWh电池储能，是PacifiCorp六州服务区内最大的光储一体设施。项目2024年9月开工，历时约21个月于2026年6月投产商运，总投资超10亿美元。运营期内预计为埃默里县学校和公共服务贡献逾5500万美元财产税。","descEn":"Utah's largest solar-plus-storage: 400 MW PV + 1.6 GWh battery, online June 2026","detailEn":"The Green River Energy Center in Emery County, Utah pairs 400 MW of solar PV with a 400 MW/1,600 MWh battery — the largest solar-plus-storage facility in PacifiCorp's six-state territory. It broke ground in September 2024 and reached commercial operation in June 2026 after ~21 months, with capital investment exceeding $1 billion. It is expected to generate over $55 million in property taxes for Emery County over its life."},
  {"id":7434,"name":"Grape 光储项目（威斯特兰太阳能园）","en":"Grape Solar & Storage Project","country":"美国","region":"北美","cat":"storage","coord":[-120.1,36.3],"cap":"246 MWac 光伏 + 150MW/600MWh 储能","inv":6,"invText":"约$6亿融资","status":"在建","year":2026,"updated":"2026-06","owner":"CIM Group / Permanent Power Company","flagship":false,"desc":"加州圣华金河谷光储项目2026年6月完成约6亿美元建设融资","detail":"位于美国加州圣华金河谷威斯特兰太阳能园区的Grape项目，含246.4MWac光伏与150MWac/600MWh电池储能。2026年6月18日，CIM Group旗下Permanent Power Company完成约6亿美元建设融资（含约3.723亿建设转定期贷款、1.667亿税收抵免过桥贷款及6130万信用证额度）以推进开发。项目预计创造逾400个建设岗位，建成后可为逾8.6万户加州家庭供电。","descEn":"California San Joaquin Valley solar-plus-storage closed ~$600M construction financing June 2026","detailEn":"The Grape project in Westlands Solar Park, California's San Joaquin Valley, comprises 246.4 MWac of solar PV and 150 MWac/600 MWh of battery storage. On 18 June 2026, CIM Group's Permanent Power Company closed an ~$600 million construction financing facility (incl. an ~$372.3M construction-to-term loan, $166.7M tax-credit bridge loan and $61.3M letter of credit) to proceed. It will support 400+ construction jobs and power over 86,000 homes."},
  {"id":7435,"name":"Clearway 谷歌绿电组合（三州风光）","en":"Clearway–Google 1.2 GW PPA Portfolio","country":"美国","region":"北美","cat":"renewable","coord":[-96.8,32.8],"cap":"近 1.2GW 风光","inv":24,"invText":"逾$24亿","status":"在建","year":2026,"updated":"2026-01","owner":"Clearway Energy（道达尔持股50%）","flagship":false,"desc":"Clearway与谷歌签近1.2GW风光PPA，横跨得州/密苏里/西弗吉尼亚，2026年开工","detail":"道达尔持股50%的美国可再生能源开发商Clearway于2026年1月与谷歌签署合计约1.17GW的购电协议组合，项目位于得克萨斯州、密苏里州和西弗吉尼亚州，覆盖ERCOT、SPP和PJM三大电力市场，为谷歌数据中心供电，期限最长20年，代表逾24亿美元清洁能源基础设施投资。逾1GW的项目在2026年开工，首批场站预计2027-2028年并网。加上已运营的71.5MW西弗吉尼亚项目，双方合作总规模达1.24GW，与道达尔另签的1GW得州光伏PPA互补。","descEn":"Clearway signed ~1.2 GW wind/solar PPAs with Google across TX/MO/WV, construction from 2026","detailEn":"Clearway (50%-owned by TotalEnergies) signed a portfolio of PPAs totaling ~1.17 GW with Google in January 2026, with projects in Texas, Missouri and West Virginia spanning the ERCOT, SPP and PJM markets to power Google data centers for up to 20 years, representing over $2.4 billion in clean-energy infrastructure. The 1 GW+ of projects begin construction in 2026 with first sites online in 2027-2028. Together with an existing 71.5 MW West Virginia project, the partnership totals 1.24 GW, complementing TotalEnergies' separate 1 GW Texas solar PPAs."},
  {"id":7436,"name":"科阿韦拉双光伏储能电站（Carbón II / Río Escondido）","en":"Coahuila Solar-plus-Storage (Carbón II / Río Escondido)","country":"墨西哥","region":"北美","cat":"renewable","coord":[-100.65,28.7],"cap":"556 MW 光伏（376+180）+ 储能","inv":8.2,"invText":"约154.5亿墨西哥比索（约$8.2亿·估）","status":"在建","year":2026,"updated":"2026-02","owner":"墨西哥联邦电力公司 CFE","flagship":false,"desc":"科阿韦拉Carbón II与Río Escondido两站合计556MW光伏配储，2026年2月开工","detail":"墨西哥CFE在科阿韦拉州建设的两座光伏电站——Carbón II（376MWac，投资约104亿比索）与Río Escondido（180MWac，投资约50.5亿比索），合计556MW并各配套相当于容量30%、时长3小时的电池储能。两站建设于2026年2月启动、贯穿至2028年，合计投资约154.5亿墨西哥比索。项目是墨西哥总统辛鲍姆电力扩张与可再生能源转型计划的组成部分，助力老煤电基地向清洁能源转型。","descEn":"Coahuila's Carbón II & Río Escondido, 556 MW PV with storage, broke ground Feb 2026","detailEn":"CFE's two solar plants in Coahuila, Mexico — Carbón II (376 MWac, ~MXN 10.4 bn) and Río Escondido (180 MWac, ~MXN 5.05 bn) — together contribute 556 MW, each backed by battery storage equal to 30% of capacity for three hours. Construction started in February 2026 and runs to 2028, at a combined ~MXN 15.45 billion. They form part of President Sheinbaum's power-expansion and renewables plan, converting a legacy coal region toward clean energy."},
  {"id":7438,"name":"Jurassic 电池储能站（阿尔伯塔）","en":"Jurassic Battery Energy Storage","country":"加拿大","region":"北美","cat":"storage","coord":[-110.5,49.9],"cap":"80MW/160MWh 储能","inv":0.86,"invText":"约$1.2亿加元（约$0.86亿·估）","status":"在建","year":2026,"updated":"2026-05","owner":"Northland Power","flagship":false,"desc":"阿尔伯塔80MW/160MWh储能达成融资关闭，2026年底投运","detail":"位于加拿大阿尔伯塔省东南部塞浦路斯县（Cypress County）的Jurassic电池储能项目，装机80MW、时长2小时（160MWh），建成后将成为阿尔伯塔省最大储能设施。Northland Power已为该项目达成融资关闭并推进建设，签有15年固定容量合同，预计2026年底投产商运，项目造价约1.2亿加元（约8600万美元），由无追索项目级融资、自有现金及流动性支持；截至2026年一季度电池组与变压器已安装、主变已带电。","descEn":"Alberta 80 MW/160 MWh battery reached financial close, online late 2026","detailEn":"The Jurassic BESS in Cypress County, southeastern Alberta, Canada, is an 80 MW, 2-hour (160 MWh) system that will be the largest in Alberta. Northland Power has reached financial close and is advancing construction under a 15-year fixed-price capacity contract, with commercial operation expected in late 2026. The project costs ~C$120 million (~US$86M), funded by non-recourse project-level financing, cash and liquidity; as of Q1 2026 its battery packs and transformers were installed and the main transformer energized."},
  {"id":7442,"name":"AWS 美国联邦 AI 与超算基础设施扩建","en":"AWS US Federal AI & Supercomputing Expansion","country":"美国","region":"北美","cat":"datacenter","coord":[-77.4875,38.9586],"cap":"跨 Top Secret/Secret/GovCloud 新增约 1.3GW AI 与超算","inv":500,"invText":"最高 $500 亿","status":"规划","year":2026,"updated":"2026-06","owner":"Amazon Web Services（服务美国联邦机构）","flagship":true,"desc":"AWS 承诺最高 500 亿美元扩建联邦级 AI 超算，2026 动工","detail":"AWS 承诺投入最高 500 亿美元，在其 Top Secret、Secret 与 GovCloud（美国）区域新增约 1.3GW 的 AI 与超级计算能力，专门服务美国联邦政府机构，计划 2026 年破土动工。项目将部署 AWS Trainium AI 芯片与 NVIDIA AI 基础设施，并向机构开放 SageMaker、Bedrock、Amazon Nova 及 Anthropic Claude 等模型，为国防、情报与民用联邦机构提供大规模安全 AI 算力，是 2026 年主权/政府级 AI 基础设施投资的标志性项目之一。","descEn":"AWS pledges up to $50B to expand federal-grade AI supercomputing, groundbreak 2026","detailEn":"AWS has committed up to $50B to add ~1.3GW of AI and supercomputing capacity across its Top Secret, Secret and GovCloud (US) regions to serve US federal agencies, with groundbreaking scheduled for 2026. It will deploy AWS Trainium AI chips and NVIDIA AI infrastructure and give agencies access to SageMaker, Bedrock, Amazon Nova and Anthropic's Claude, providing large-scale secure AI compute to defense, intelligence and civilian federal agencies — a landmark government/sovereign AI infrastructure investment of 2026."},
  {"id":7449,"name":"美国凯默勒 Natrium 钠冷快堆电站","en":"TerraPower Natrium Kemmerer Unit 1","country":"美国","region":"北美","cat":"nuclear","coord":[-110.5474,41.7924],"cap":"345MWe（钠冷快堆，可蓄热提升至500MWe）","inv":40,"invText":"约$40亿（估）","status":"在建","year":2026,"updated":"2026-04","owner":"TerraPower（比尔·盖茨创立）","flagship":true,"desc":"美国近十年首座获批开建的商用先进反应堆正式开工核岛","detail":"位于美国怀俄明州凯默勒（Kemmerer）的 TerraPower Natrium 钠冷快堆一号机组，装机345MWe、配熔盐储热可短时提升至500MWe。2026年3月4日 NRC 颁发 Part 50 建设许可——这是该机构近十年来首次批准商用反应堆建设、也是40多年来首个获批的商用非轻水堆设计。2026年4月23日核岛正式开工（非核部分2024年6月已动工），有望成为美国首座公用事业级先进核电站。","descEn":"First US commercial advanced reactor to break ground on its nuclear island in a decade","detailEn":"TerraPower's Natrium sodium-cooled fast reactor Unit 1 in Kemmerer, Wyoming, is rated 345 MWe with molten-salt thermal storage that can briefly boost output to 500 MWe. On 4 March 2026 the NRC issued a Part 50 construction permit—the agency's first approval of a commercial reactor in nearly a decade and the first for a commercial non-light-water design in over 40 years. Nuclear-island construction officially began on 23 April 2026 (non-nuclear work started in June 2024), on track to be the first utility-scale advanced nuclear plant in the US."},
  {"id":7451,"name":"Delfin FLNG 1 浮式液化天然气出口项目","en":"Delfin FLNG 1 Floating LNG Export Project","country":"美国","region":"北美","cat":"petro","coord":[-93.15,29.15],"cap":"4.4 MTPA LNG（浮式，美国首个）","inv":50,"invText":"约$50亿","status":"在建","year":2030,"updated":"2026-06","owner":"Delfin Midstream（BlackRock GIP领投）","flagship":true,"desc":"美国首个浮式LNG项目达成50亿美元FID","detail":"2026年6月3日，Delfin Midstream对位于路易斯安那州卡梅伦教区外海约40海里墨西哥湾的Delfin FLNG 1作出50亿美元最终投资决定，成为美国获批的首个浮式液化天然气出口项目。由BlackRock旗下Global Infrastructure Partners领投、三井/Vitol/Diamond Capital等参与，三星重工与Black & Veatch承建。单船出口能力约440万吨/年，为全球FLNG最大，计划2030年投产；已与Vitol、Expand Energy、Centrica、Gunvor签署长期购销协议。","descEn":"US first floating LNG project reaches $5B FID","detailEn":"On June 3, 2026, Delfin Midstream took a $5 billion final investment decision on Delfin FLNG 1, sited roughly 40 nautical miles offshore Cameron Parish, Louisiana in the Gulf of Mexico. It is the first floating LNG export project sanctioned in the US, led by BlackRock's Global Infrastructure Partners with Mitsui, Vitol and Diamond Capital, and built turnkey by Samsung Heavy Industries and Black & Veatch. Its ~4.4 MTPA single-vessel capacity is the largest of any FLNG globally, with first production targeted for 2030 and long-term offtake signed with Vitol, Expand Energy, Centrica and Gunvor."},
  {"id":7452,"name":"Commonwealth LNG 路易斯安那出口终端","en":"Commonwealth LNG Export Terminal","country":"美国","region":"北美","cat":"petro","coord":[-93.32,29.8],"cap":"9.5 MTPA LNG","inv":130,"invText":"约$130亿（融资97.5亿）","status":"在建","year":2030,"updated":"2026-05","owner":"Caturus（Mubadala/Kimmeridge/CPP）","flagship":true,"desc":"9.5百万吨/年LNG项目达成130亿美元FID","detail":"2026年5月15日，Caturus宣布对位于路易斯安那州卡梅伦教区的Commonwealth LNG出口终端作出正面最终投资决定，并完成97.5亿美元项目融资，由20家国际银行组成的银团提供，总认购意向达212.5亿美元。项目产能950万吨/年，总投资约130亿美元，计划2030年投产。股东包括Mubadala Energy、Kimmeridge、CPP Investments与Ares，长期购销方含EQT、Glencore、Mercuria、PETRONAS与Aramco Trading。","descEn":"9.5 MTPA LNG project reaches $13B FID","detailEn":"On May 15, 2026, Caturus announced a positive FID for the Commonwealth LNG export terminal in Cameron Parish, Louisiana, closing $9.75 billion of project financing from a 20-bank international syndicate against $21.25 billion of total commitments. The 9.5 MTPA facility carries a ~$13 billion total cost and targets first LNG in 2030. Backers include Mubadala Energy, Kimmeridge, CPP Investments and Ares, with offtake from EQT, Glencore, Mercuria, PETRONAS and Aramco Trading."},
  {"id":7455,"name":"Big Sky 氦气·碳捕集处理枢纽（蒙大拿）","en":"Big Sky Carbon Hub (Montana)","country":"美国","region":"北美","cat":"petro","coord":[-108.5,45.78],"cap":"进气约800万立方英尺/日（氦气+CO₂捕集）","inv":3,"invText":"约$3亿（估）","status":"在建","year":2027,"updated":"2026-03","owner":"U.S. Energy Corp / CANUSA EPC","flagship":false,"desc":"蒙大拿Big Sky氦气·碳捕集枢纽2026年3月达成FID","detail":"2026年3月18日，U.S. Energy Corp（纳斯达克:USEG）对位于蒙大拿州的Big Sky处理枢纽一期作出最终投资决定，并与CANUSA EPC签署固定范围EPC总承包协议，目标2027年一季度商业运营。装置进气约800万立方英尺/日，初期年产约1400万立方英尺高纯氦气与约12.5万吨精制CO₂，符合45Q约85美元/吨税收抵免、一期抵免价值约1.3亿美元，是美国天然气处理+碳捕集封存全链条工程之一。","descEn":"Montana's Big Sky helium & carbon capture hub reaches FID in March 2026","detailEn":"On March 18, 2026, U.S. Energy Corp (Nasdaq: USEG) took a final investment decision on Phase 1 of its Big Sky processing hub in Montana and signed a fixed-scope EPC agreement with CANUSA EPC, targeting commercial operations in Q1 2027. The plant is designed for ~8 MMcf/d of inlet, producing ~14 MMcf/year of high-purity helium and ~125,000 t/year of refined CO2 at start-up, qualifying for ~$85/tonne 45Q credits with ~$130 million of Phase-1 credit value, a full-chain US gas-processing plus carbon-capture-and-storage project."},
  {"id":7457,"name":"NET Power 二叠纪零碳天然气电站（Project Permian）","en":"NET Power Project Permian","country":"美国","region":"北美","cat":"petro","coord":[-102.08,31.85],"cap":"80MW（一期）+ 燃后CO₂捕集","inv":11,"invText":"约$11亿（估）","status":"规划","year":2029,"updated":"2026-03","owner":"NET Power / 西门子能源 / Entropy","flagship":false,"desc":"NET Power二叠纪零碳天然气电站FID预计2026下半年","detail":"NET Power位于美国得州二叠纪盆地、Occidental托管场地（临近敖德萨）的Project Permian采用西门子能源A35燃机搭配Entropy燃后碳捕集技术，一期规划80MW电力输出。公司与Entropy力争2026年二季度敲定最终协议，最终投资决定预计2026年下半年作出，目标2029年初商业运营，由Occidental负责CO₂输送与封存，将成为美国首个商业化清洁天然气发电项目。","descEn":"NET Power's zero-carbon gas plant in the Permian eyes 2H-2026 FID","detailEn":"NET Power's Project Permian at an Occidental-hosted site near Odessa in the Permian Basin, Texas uses Siemens Energy A35 gas turbines paired with Entropy's post-combustion capture, targeting 80 MW of electrical output in Phase 1. The company and Entropy aim to finalize definitive agreements in Q2 2026, with a final investment decision expected in 2H 2026 and commercial operations by early 2029; Occidental handles CO2 transport and sequestration, making it the first commercial clean gas power project in the US."},
  {"id":7468,"name":"蒙特利尔康特勒克尔集装箱码头扩建","en":"Port of Montreal Contrecoeur Container Terminal","country":"加拿大","region":"北美","cat":"transport","coord":[-73.22,45.83],"cap":"新增约115万TEU/年，港口吞吐能力提升约60%","inv":12,"invText":"约12亿美元（$1.2B）","status":"在建","year":2030,"updated":"2026-04","owner":"蒙特利尔港务局 / Pomerleau-Aecon联合体","flagship":false,"desc":"蒙特利尔康特勒克尔集装箱码头2026年4月开工，扩能60%","detail":"2026年4月9日，加拿大总理卡尼为蒙特利尔港康特勒克尔集装箱码头扩建主持开工，项目位于圣劳伦斯河畔。首期水工工程（含疏浚与码头岸壁）自2025年10月起由Pomerleau（60%）与Aecon（40%）联合体承建。融资含加拿大基础设施银行约11.6亿加元贷款，另有魁北克省1.3亿加元、联邦运输部1.5亿加元出资。项目新建码头，港口集装箱吞吐能力提升约60%、年增最多115万TEU，二期2027年启动，2030年全面投运。","descEn":"Montreal's Contrecoeur container terminal broke ground Apr 2026, +60% capacity","detailEn":"On 9 April 2026 Canadian PM Mark Carney broke ground on the Contrecoeur container-terminal expansion at the Port of Montreal on the St. Lawrence River. Phase-1 in-water works (dredging and quay walls) have run since Oct 2025 under a Pomerleau (60%)–Aecon (40%) JV. Financing includes ~C$1.16B from the Canada Infrastructure Bank plus C$130M from Quebec and C$150M from Transport Canada. The new terminal lifts container capacity by ~60%, adding up to 1.15M TEU/year; Phase 2 starts 2027 with full operation in 2030."},
  {"id":7469,"name":"墨西哥瓜伊马斯港扩建（含AMIGO LNG）","en":"Port of Guaymas Expansion (with AMIGO LNG)","country":"墨西哥","region":"北美","cat":"transport","coord":[-110.9,27.92],"cap":"港口综合扩建，含AMIGO LNG液化天然气出口码头（780万吨/年）","inv":75,"invText":"约75亿美元（MX$1300亿）","status":"在建","year":2030,"updated":"2026-03","owner":"墨西哥海军（SEMAR） / AMIGO LNG","flagship":false,"desc":"瓜伊马斯港1300亿比索扩建2026年启动，含LNG出口码头","detail":"墨西哥总统辛鲍姆2026年2月宣布，价值1300亿墨西哥比索（约75亿美元）的新一轮私人投资于2026年一季度启动瓜伊马斯港扩建，由墨西哥海军（SEMAR）主导。核心项目为AMIGO LNG液化天然气出口码头，年产能780万吨、面向印度日本印尼等市场，据地方官员称2026年3月起动工、2028年投产，COMSA Marine获海工EPC合同。配套修建赫莫西约—瓜伊马斯输气管道，该港位于索诺拉州太平洋沿岸。","descEn":"Guaymas port MX$130B expansion kicks off 2026, includes LNG export terminal","detailEn":"President Sheinbaum announced in Feb 2026 a new wave of private investment worth MX$130B (~$7.5B) launching in Q1 2026 to expand the Port of Guaymas, led by the Mexican Navy (SEMAR). A central pillar is an AMIGO LNG export terminal (7.8M t/year, targeting India, Japan and Indonesia) which local officials say began construction in March 2026 for a 2028 start-up, with COMSA Marine holding the marine EPC. A new Hermosillo–Guaymas pipeline supports it; the port sits on Sonora's Pacific coast."},
  // ===== 南美（7437-7461）=====
  {"id":7437,"name":"圣拉斐尔太阳能园（门多萨）","en":"San Rafael Solar Park","country":"阿根廷","region":"南美","cat":"renewable","coord":[-68.33,-34.62],"cap":"200 MW 光伏（2026年初首批140MW投运）","inv":2.2,"invText":"$2.2亿","status":"投运","year":2026,"updated":"2026-01","owner":"Verano Energy","flagship":false,"desc":"门多萨圣拉斐尔太阳能园2026年初首批140MW并网投运","detail":"位于阿根廷门多萨省圣拉斐尔的太阳能园，由Verano Energy开发，总投资2.2亿美元。项目2024年10月底破土，2026年1月首批140MW并网投产商运，可为约13.5万户家庭供电，总规模200MW。项目所在地日照资源优越、地形理想且紧邻变电站，助力门多萨省两年内新增700MW光伏的目标，是阿根廷可再生能源扩张的代表项目之一。","descEn":"Mendoza's San Rafael solar brought a first 140 MW online in January 2026","detailEn":"The San Rafael Solar Park in Mendoza province, Argentina, developed by Verano Energy at a total $220 million. It broke ground in late October 2024 and brought a first 140 MW online in January 2026, powering ~135,000 homes, toward a 200 MW total. The site benefits from high irradiation, ideal terrain and proximity to a substation, supporting Mendoza's goal of adding 700 MW of solar, and representing Argentina's renewable expansion."},
  {"id":7459,"name":"智利埃斯孔迪达新选矿厂环评申报","en":"BHP Escondida New Concentrator EIA Filing","country":"智利","region":"南美","cat":"mining","coord":[-69.05,-24.28],"cap":"新建选矿厂设计产铜22万-26万吨/年，维持46万吨/日硫化矿处理量","inv":52,"invText":"$44亿-59亿","status":"规划","year":2026,"updated":"2026-03","owner":"必和必拓（BHP）","flagship":true,"desc":"全球最大铜矿新选矿厂2026年3月递交环评，投资44亿-59亿美元","detail":"埃斯孔迪达位于智利安托法加斯塔大区阿塔卡马沙漠，是全球最大铜矿。必和必拓于2026年3月通过环境影响声明（EID）向智利环评系统递交\"埃斯孔迪达新选矿厂\"项目，投资44亿-59亿美元，用以替代寿命将尽的Los Colorados选矿厂、维持46万吨/日硫化矿处理能力（新选矿厂设计产铜22万-26万吨/年）。若获批，建设或于2027年初启动，首产预计2031-2032年，是必和必拓约108亿美元十年增长计划的核心棕地项目。","descEn":"World's largest copper mine filed its new-concentrator EIA in March 2026; $4.4-5.9B","detailEn":"Escondida in Chile's Antofagasta region (Atacama desert) is the world's largest copper mine. In March 2026 BHP lodged its \"New Escondida Concentrator\" with Chile's environmental system via an Environmental Impact Declaration, investing US$4.4-5.9 billion to replace the ageing Los Colorados plant and maintain 460,000 t/d of sulphide-ore throughput (the new concentrator is designed for 220,000-260,000 t/yr of copper). If approved, construction could start in early 2027 with first production expected around 2031-2032 — a core brownfield element of BHP's ~US$10.8 billion, 10-year growth plan."},
  {"id":7460,"name":"智利安托法加斯塔铜矿扩建计划2026","en":"Antofagasta Copper Expansion Programme 2026","country":"智利","region":"南美","cat":"mining","coord":[-70.28,-31.75],"cap":"2026年资本开支34亿美元，投向Centinela二期选矿厂与Los Pelambres","inv":34,"invText":"$34亿","status":"在建","year":2026,"updated":"2026-06","owner":"安托法加斯塔（Antofagasta PLC）","flagship":false,"desc":"智利安托集团2026年资本开支34亿美元加速铜扩产","detail":"英资安托法加斯塔集团2026年资本开支约34亿美元（不含Zaldívar），投向Centinela第二选矿厂、Los Pelambres建设及Centinela的Encuentro硫化矿露天坑扩建。Centinela二期选矿厂计划2027年建成，Los Pelambres海水淡化厂扩能与管线工程持续推进。集团2026年铜产量指引65万-70万吨，主要受Los Pelambres品位提升拉动，顺应2026年偏紧的铜市场。","descEn":"Chile's Antofagasta commits ~$3.4B of 2026 capex to accelerate copper expansion","detailEn":"UK-listed Antofagasta plans ~US$3.4 billion of capex in 2026 (excluding Zaldívar), directed at Centinela's second concentrator, construction at Los Pelambres and the expansion of Centinela's Encuentro sulphides pit. The Centinela second concentrator is due for completion in 2027, while the Los Pelambres desalination-plant expansion and pipeline work continue. Group 2026 copper guidance is 650,000-700,000 t, driven by higher Los Pelambres grades in a tight 2026 market."},
  {"id":7461,"name":"阿根廷Kachi锂盐湖DLE项目","en":"Kachi Lithium Brine DLE Project","country":"阿根廷","region":"南美","cat":"mining","coord":[-66.95,-26.05],"cap":"一期2.5万吨/年碳酸锂当量，25年矿山寿命","inv":11.6,"invText":"$11.6亿","status":"规划","year":2026,"updated":"2026-06","owner":"Lake Resources（湖资源）","flagship":false,"desc":"阿根廷卡塔马卡DLE锂项目，2026年目标环评批准与FID","detail":"Kachi锂盐湖直接提锂（DLE）项目位于阿根廷卡塔马卡省锂三角，由澳大利亚湖资源（Lake Resources）开发，一期设计年产2.5万吨碳酸锂、矿山寿命25年，一期资本开支约11.57亿美元、税后NPV约14.7亿美元、IRR约22.5%。2026年公司正推进采矿环评（EIA）审批，已收到卡塔马卡当局正式意见并准备答复，目标2026年第三季度获得EIA批准，并计划在2026年内作出最终投资决定（FID）。","descEn":"Argentine DLE lithium project targeting EIA approval and FID in 2026","detailEn":"The Kachi Direct-Lithium-Extraction (DLE) brine project in Catamarca province, Argentina (lithium triangle) is developed by Australia's Lake Resources — Phase 1 designed for 25,000 t/yr lithium carbonate over a 25-year life, with ~US$1.157 billion Phase 1 capex, a post-tax NPV of ~US$1.47 billion and ~22.5% IRR. Through 2026 the company is advancing its exploitation EIA (formal observations received from Catamarca authorities), targeting EIA approval in Q3 2026 and a Final Investment Decision within 2026."},
  // ===== 非洲（7404-7464）=====
  {"id":7404,"name":"Scatec 埃及 1.95GW 光伏+3.9GWh 储能一揽子项目","en":"Scatec Egypt 1.95 GW Solar + 3.9 GWh BESS Portfolio","country":"埃及","region":"非洲","cat":"renewable","coord":[31.5,27.5],"cap":"1.95GW 光伏 + 3.9GWh 储能","inv":22,"invText":"约$22亿(估，财务关闭时披露)","status":"规划","year":2028,"updated":"2026-01","owner":"Scatec ASA / 埃及输电公司(EETC)","flagship":true,"desc":"非洲最大光储一揽子项目，25年美元PPA","detail":"2026年1月11日，挪威Scatec与埃及输电公司(EETC)签署里程碑式PPA，涵盖1.95GW光伏与3.9GWh电池储能：一个光储混合系统提供全天候基荷电力，另有两个独立储能项目提供电网支撑。采用25年美元计价、按发电量结算的PPA，年发电约6000GWh，为Scatec史上最大投资、非洲最大光储装置。Scatec负责EPC、资产管理与运维，财务关闭预计2026年下半年。","descEn":"Africa's largest solar-plus-storage portfolio under a 25-year USD PPA","detailEn":"On 11 Jan 2026 Scatec signed a landmark PPA with Egypt's EETC covering 1.95 GW of solar and 3.9 GWh of BESS: one integrated solar+BESS hybrid delivering round-the-clock baseload plus two standalone storage projects for grid support. The 25-year USD pay-as-produced PPA implies ~6,000 GWh/year. Scatec provides EPC, asset management and O&M; it is the company's largest-ever investment and Africa's largest solar-plus-storage installation, with financial close expected in H2 2026."},
  {"id":7405,"name":"AMEA Power 阿拜多斯二期(Abydos II)光储项目","en":"AMEA Power Abydos II Solar + BESS, Egypt","country":"埃及","region":"非洲","cat":"renewable","coord":[32.9,24.4],"cap":"1GW 光伏 + 600MWh 储能","inv":7,"invText":"约$7亿(IFC牵头$5.7亿高级债务)","status":"在建","year":2026,"updated":"2026-04","owner":"AMEA Power (阿联酋) / Kyuden","flagship":false,"desc":"阿斯旺1GW光伏+600MWh储能，非洲最大单场址项目","detail":"阿联酋AMEA Power与日本九电国际(Kyuden)在埃及阿斯旺省开发的阿拜多斯二期(Abydos II)项目，规模1GW光伏配套600MWh电池储能。世界银行下属IFC牵头约5.7亿美元高级债务融资，项目公司由AMEA Power持股60%、Kyuden持股40%。称为'非洲最大单场址可再生能源+电池项目'，预计2026年6月实现商业运营，显著提升埃及电力安全与调峰能力。","descEn":"1 GW Aswan solar + 600 MWh storage, Africa's largest single-site project","detailEn":"AMEA Power (UAE) and Japan's Kyuden International are developing Abydos II in Aswan Governorate, Egypt—1 GW of solar paired with a 600 MWh BESS. The World Bank's IFC leads a ~$570M senior debt package; the project company is 60% AMEA Power and 40% Kyuden. Billed as Africa's largest single-site renewables-and-battery project, it targets commercial operation in June 2026, strengthening Egypt's energy security and dispatchability."},
  {"id":7406,"name":"ACWA Power 埃及2GW苏伊士湾风电场","en":"ACWA Power 2 GW Gulf of Suez Wind Farm, Egypt","country":"埃及","region":"非洲","cat":"renewable","coord":[33.05,28.35],"cap":"2GW 陆上风电","inv":23,"invText":"$23亿","status":"规划","year":2027,"updated":"2026-05","owner":"ACWA Power (沙特)","flagship":true,"desc":"埃及最大2GW单体风电IPP，23亿美元","detail":"沙特ACWA Power与埃及输电公司(EETC)签署约23亿美元、25年PPA协议，在埃及苏伊士湾地区开发2GW陆上风电场，为埃及最大单体IPP风电项目，超越1.1GW苏伊士风电。目标2026年内实现财务关闭，将ACWA在埃及可再生能源总投资推高至约88亿美元、总装机4.8GW，巩固其埃及及非洲最大可再生能源开发商地位，年减碳超350万吨。","descEn":"Egypt's largest single-asset 2 GW wind IPP, worth $2.3bn","detailEn":"Saudi Arabia's ACWA Power signed a ~$2.3bn, 25-year PPA with Egypt's EETC to build a 2 GW onshore wind farm in the Gulf of Suez region—the country's largest single-asset IPP, surpassing the 1.1 GW Suez facility. Targeting financial close in 2026, it lifts ACWA's Egyptian renewable investment to ~$8.8bn and 4.8 GW gross capacity and cuts over 3.5 Mt of CO2 annually."},
  {"id":7407,"name":"ORNX 摩洛哥拉尤内绿氨项目","en":"ORNX Laayoune Green Ammonia Project, Morocco","country":"摩洛哥","region":"非洲","cat":"renewable","coord":[-13.2,27.15],"cap":"2GW+ 风光 + 900MW 电解 + 储能(年产10万吨氢/56万吨氨)","inv":45,"invText":"$45亿","status":"规划","year":2030,"updated":"2026-02","owner":"ORNX 联合体(Ortus/Acciona/Nordex)","flagship":true,"desc":"拉尤内45亿美元绿氨，2GW+风光配套","detail":"2026年2月，由美国Ortus、西班牙Acciona与德国Nordex组成的ORNX联合体与摩洛哥政府签署协议，投资45亿美元在南部拉尤内(Laayoune)地区开发绿氨项目：一期年产约10万吨绿氢、56万吨绿氨，配套2GW以上风光发电、约900MW电解及海水淡化与电池储能，为摩洛哥最大清洁能源投资之一，产品面向国内使用及欧洲出口。ORNX另计划在Boujdour与Dakhla开发后续项目。","descEn":"$4.5bn Laayoune green ammonia with 2 GW+ of wind and solar","detailEn":"In Feb 2026 the ORNX consortium (Ortus of the US, Acciona of Spain, Nordex of Germany) signed with Morocco's government to invest $4.5bn in a green ammonia project in southern Laayoune: a first phase of ~100,000 t/yr hydrogen and 560,000 t/yr ammonia, powered by 2 GW+ of wind and solar, ~900 MW of electrolysers, plus desalination and battery storage—one of Morocco's largest clean-energy investments, for domestic use and European export. ORNX also plans follow-on sites at Boujdour and Dakhla."},
  {"id":7408,"name":"Mulilo Hartebeesfontein 电池储能项目","en":"Mulilo Hartebeesfontein BESS, South Africa","country":"南非","region":"非洲","cat":"storage","coord":[26.85,-26.77],"cap":"77MW / 308MWh 储能","inv":1.5,"invText":"约$1.5亿(估)","status":"在建","year":2027,"updated":"2026-06","owner":"Mulilo / Reatile Group","flagship":false,"desc":"西北省77MW/308MWh储能达成财务关闭","detail":"2026年6月，Mulilo宣布位于南非西北省Klerksdorp(Matlosana市)附近的Hartebeesfontein 77MW/308MWh电池储能项目达成财务关闭，为其2026年内第5个关闭的项目，也是其在储能独立发电商采购计划(BESIPPPP)第二轮所获项目之一。项目临近Eskom的Hermes主输电变电站，通过15年PPA向南非国家输电公司(NTCSA)提供辅助服务；融资由Absa、Standard Bank、Nedbank及CIP、Norfund支持。","descEn":"77 MW/308 MWh North West Province battery reaches financial close","detailEn":"In June 2026 Mulilo reached financial close on the 77 MW/308 MWh Hartebeesfontein BESS near Klerksdorp (Matlosana), North West Province—its fifth project to close in 2026 under Bid Window 2 of South Africa's BESIPPPP. Sited near Eskom's Hermes transmission substation, it supplies ancillary services to NTCSA under a 15-year PPA, financed by Absa, Standard Bank and Nedbank plus Copenhagen Infrastructure Partners and Norfund."},
  {"id":7409,"name":"Naos-1 混合光储项目(SOLA/远景)","en":"Naos-1 Hybrid Solar + Storage, South Africa","country":"南非","region":"非洲","cat":"storage","coord":[26.95,-27.2],"cap":"300MW 光伏 + 660MWh 储能","inv":3,"invText":"约$3亿(估)","status":"在建","year":2027,"updated":"2026-06","owner":"SOLA Group / WBHO / 远景能源(Envision)","flagship":false,"desc":"自由州最大私营混合项目，远景供660MWh储能","detail":"2026年6月25日，远景能源(Envision)与SOLA集团、WBHO签署660MWh电池储能供货协议，用于南非自由州Viljoenskroon附近的Naos-1混合可再生项目。项目结合300MW光伏与660MWh储能，通过电网'转供(wheeling)'向多个工商业大用户输送可调度绿电，为南非最大已达财务关闭的私营混合可再生项目；远景与SOLA另签25年长期服务协议(LTSA)负责储能系统运维。","descEn":"Free State's largest private hybrid project; Envision supplies 660 MWh BESS","detailEn":"On 25 June 2026 Envision Energy signed a 660 MWh BESS supply deal with SOLA Group and WBHO for the Naos-1 hybrid project near Viljoenskroon, Free State. Combining 300 MW of solar with 660 MWh of storage, it wheels dispatchable green power across the national grid to large C&I offtakers—South Africa's largest privately contracted hybrid renewable project to reach financial close; Envision and SOLA also signed a 25-year LTSA for the storage system."},
  {"id":7410,"name":"GridWorks 埃塞俄比亚-吉布提输电项目","en":"GridWorks Ethiopia–Djibouti Transmission Project","country":"埃塞俄比亚","region":"非洲","cat":"grid","coord":[41.9,9.6],"cap":"400kV 198km(Hurso–Ayisha)+ 第二条优先线路","inv":4,"invText":"$4亿","status":"规划","year":2028,"updated":"2026-02","owner":"GridWorks (英国, BII支持)","flagship":false,"desc":"埃塞首个私营输电PPP，400kV接入吉布提","detail":"2026年2月，英国GridWorks(BII支持)与埃塞财政部及埃塞电力公司(EEP)签署约4亿美元联合开发协议，开发两个优先输电项目，其中一条为198km、400kV的Hurso–Ayisha线路，强化埃塞东北部新能源接入及与吉布提的跨境电力互联互通。这是埃塞首个私营融资输电PPP项目，服务于GERD大坝满发后的电力外送与区域电力贸易，助力开发东北部风光资源。","descEn":"Ethiopia's first private transmission PPP, 400 kV link toward Djibouti","detailEn":"In Feb 2026 Britain's GridWorks (backed by BII) signed a ~$400M Joint Development Agreement with Ethiopia's Ministry of Finance and Ethiopian Electric Power for two priority transmission projects, including a 198 km, 400 kV Hurso–Ayisha line that strengthens renewable access in the northeast and the interconnection with Djibouti. It is Ethiopia's first privately financed transmission PPP, supporting power exports and regional trade after the GERD dam's ramp-up and unlocking northeastern wind and solar."},
  {"id":7411,"name":"Masdar Quipungo 光伏电站(安哥拉)","en":"Masdar Quipungo Solar PV, Angola","country":"安哥拉","region":"非洲","cat":"renewable","coord":[14.95,-14.85],"cap":"150MW 光伏(Royal Sable计划共500MW)","inv":1.5,"invText":"约$1.5亿(估)","status":"规划","year":2028,"updated":"2026-01","owner":"Masdar (阿联酋)","flagship":false,"desc":"Masdar在安哥拉首个光伏PPA，150MW","detail":"2026年1月，在IRENA大会(阿布扎比可持续周)期间，阿联酋Masdar与安哥拉国家输电公司(RNT-EP)签署150MW Quipungo光伏电站PPA，位于南部威拉省(Huila)。这是Masdar在安哥拉的首个签约项目，也是其'Royal Sable'计划(三处场址共500MW可再生能源)下首个落地场址，获IRENA的ETAF融资机制支持。项目建成后可为约30万户家庭供电，整个500MW组合可创造逾2000个就业岗位。","descEn":"Masdar's first Angola solar PPA, 150 MW in Huila Province","detailEn":"In Jan 2026, on the sidelines of the IRENA General Assembly during Abu Dhabi Sustainability Week, Masdar signed a PPA with Angola's national transmission company (RNT-EP) for the 150 MW Quipungo solar farm in southern Huila Province. It is Masdar's first contracted project in Angola and the first site under its 'Project Royal Sable', a 500 MW renewables programme across three sites, supported by IRENA's ETAF facility. Once complete it can power ~300,000 homes, with the wider 500 MW portfolio creating over 2,000 jobs."},
  {"id":7456,"name":"刚果Nguya浮式LNG（Congo LNG二期）","en":"Congo Nguya FLNG (Congo LNG Phase 2)","country":"刚果共和国","region":"非洲","cat":"petro","coord":[11.6,-4.9],"cap":"新增液化产能，项目总规模达3 MTPA","inv":12,"invText":"约$12亿（估）","status":"投运","year":2026,"updated":"2026-02","owner":"Eni（刚果LNG）","flagship":false,"desc":"刚果Nguya浮式LNG单元2026年2月首船出运","detail":"由Eni主导的刚果LNG项目二期位于大西洋海岸外海，2025年12月提前启动，2026年2月7日随Nguya浮式LNG单元实现首船LNG出运，刚果共和国总统与Eni CEO出席庆典。Nguya船体长376米、宽60米，将刚果总液化产能提升至约300万吨/年（约45亿立方米/年），配套三座生产平台与Scarabeo 5气体处理装置，标志刚果天然气货币化进入规模化第二阶段。","descEn":"Congo's Nguya FLNG ships its first cargo in February 2026","detailEn":"Eni's Congo LNG Phase 2, offshore the Republic of Congo's Atlantic coast, started ahead of schedule in December 2025 and shipped its first LNG cargo on February 7, 2026 from the Nguya floating LNG unit, celebrated by Congo's president and Eni's CEO. The 376 m by 60 m Nguya lifts the country's total liquefaction capacity to about 3 MTPA (~4.5 bcm/year), supported by three production platforms and the Scarabeo 5 gas-treatment unit, marking the scale-up second phase of its gas monetisation."},
  {"id":7458,"name":"刚果金卡莫阿-卡库拉四期扩建研究","en":"Kamoa-Kakula Phase 4 Expansion Study","country":"刚果（金）","region":"非洲","cat":"mining","coord":[25.42,-10.78],"cap":"四期为复制既有选矿设计的扩建方案，仍处研究阶段","inv":17,"invText":"约$17亿（估）","status":"规划","year":2026,"updated":"2026-06","owner":"艾芬豪矿业 / 紫金矿业 / 刚果金政府","flagship":false,"desc":"全球最大铜矿之一四期扩建仍处研究阶段，2026恢复产能","detail":"位于刚果（金）卢阿拉巴省的卡莫阿-卡库拉铜矿是非洲最大、全球品位最高的铜矿之一，由艾芬豪矿业与紫金矿业各持约39.6%的合资项目运营，刚果金政府持股20%。矿区50万吨/年直接吹炼粗铜冶炼厂于2025年11月21日启动，12月29日产出首批阳极铜。受2025年检修影响，2026年铜阳极产量指引下调至29万-33万吨，2027年回升至38万-42万吨，2028年起年化产能有望超50万吨。复制既有选矿设计的四期扩建目前仍是资源基础提供的扩产选项/研究方案，尚未正式核准开工。","descEn":"World's largest-tier copper mine's Phase 4 is still a study scenario; 2026 output recovers","detailEn":"The Kamoa-Kakula copper complex in Lualaba province, DRC, is one of Africa's largest and highest-grade copper mines, operated as a JV in which Ivanhoe Mines and Zijin Mining each hold ~39.6% and the DRC government 20%. Its on-site 500,000 t/yr direct-to-blister smelter started up on 21 Nov 2025 and produced first anode copper on 29 Dec 2025. After 2025 disruptions, 2026 copper-anode guidance was cut to 290,000-330,000 t, recovering to 380,000-420,000 t in 2027 and 500,000+ t/yr from 2028. A Phase 4 replicating the existing concentrator design remains an expansion option/study scenario, not yet formally sanctioned."},
  {"id":7462,"name":"马拉维Kangankunde稀土项目","en":"Kangankunde Rare Earth Project","country":"马拉维","region":"非洲","cat":"mining","coord":[35.05,-15.15],"cap":"一期1.53万吨/年独居石精矿（55% TREO）","inv":1,"invText":"约$1亿（估）","status":"在建","year":2026,"updated":"2026-06","owner":"Lindian Resources","flagship":false,"desc":"马拉维稀土项目FID后推进，2026年四季度首产","detail":"Kangankunde稀土项目位于马拉维南部Balaka附近，由澳大利亚Lindian Resources开发，2025年8月作出FID并获约5900万美元资金承诺，项目已全面获批。一期设计年产约1.53万吨55% TREO高品位独居石精矿（无有害元素），战略伙伴Iluka Resources提供2000万美元建设贷款及15年包销协议。截至2026年中，已囤积约2.7万吨矿石、逾3300名工人在场，一期采坑运输道路完工、炸药到场；前端调试目标2026年10月，实用竣工瞄准11月中，四季度首产。","descEn":"Post-FID Malawi rare-earth project advancing to first production in Q4 2026","detailEn":"The Kangankunde rare-earth project near Balaka in southern Malawi is developed by Australia's Lindian Resources, which took FID in Aug 2025 with ~US$59 million committed and the project fully permitted. Phase 1 targets ~15,300 t/yr of high-grade 55% TREO monazite concentrate (no deleterious elements), with Iluka Resources as strategic partner providing a US$20 million construction loan and a 15-year offtake. By mid-2026 ~27,000 t of ore is stockpiled and 3,300+ workers are on site; the haul road is complete and explosives are on site, with front-end commissioning targeted for Oct 2026 and first production in Q4 2026."},
  {"id":7463,"name":"马拉维Songwe Hill稀土项目","en":"Songwe Hill Rare Earth Project","country":"马拉维","region":"非洲","cat":"mining","coord":[35.55,-15.6],"cap":"碳酸岩型NdPr稀土矿，初始资本开支约3.26亿美元","inv":3.26,"invText":"约$3.26亿（初始资本开支）","status":"规划","year":2026,"updated":"2026-03","owner":"Mkango Resources","flagship":false,"desc":"马拉维稀土项目2026年3月更新DFS，税后NPV约3.39亿美元","detail":"Songwe Hill稀土项目位于马拉维Phalombe地区，为碳酸岩型NdPr（镨钕）稀土矿床，由Mkango Resources开发。2026年3月19日发布更新的最终可行性研究（DFS），初始资本开支约3.255亿美元，税后净现值约3.39亿美元（10%折现率）、内部收益率24%、满产后回收期3.4年、运营期税后现金流约15.5亿美元。配套的波兰Puławy分离厂税后NPV约7.79亿美元。项目是中国以外稀土供应链多元化的重点非洲项目之一，正推进融资与开发决策。","descEn":"Malawi rare-earth project published an updated DFS in March 2026 with ~$339M NPV","detailEn":"The Songwe Hill rare-earth project in the Phalombe district of Malawi is a carbonatite NdPr deposit developed by Mkango Resources. An updated Definitive Feasibility Study published on 19 March 2026 estimated initial capex of ~US$325.5 million, a post-tax NPV of ~US$339 million (10% discount rate), a 24% IRR, a 3.4-year payback from full production and ~US$1.55 billion of post-tax life-of-operations cash flow. A linked Puławy separation plant in Poland carries a ~US$779 million post-tax NPV. It is among the key African projects diversifying the rare-earth supply chain outside China, now advancing financing and development decisions."},
  {"id":7464,"name":"埃塞俄比亚比绍夫图国际机场","en":"Bishoftu International Airport","country":"埃塞俄比亚","region":"非洲","cat":"transport","coord":[39.03,8.72],"cap":"首期6000万人次/年，终期1.1亿人次/年，4条跑道","inv":125,"invText":"约125亿美元（$12.5B）","status":"在建","year":2030,"updated":"2026-01","owner":"埃塞俄比亚航空 / Zaha Hadid Architects","flagship":true,"desc":"非洲最大机场2026年1月动工，终期年吞吐1.1亿人次","detail":"位于亚的斯亚贝巴东南约45公里的比绍夫图市，2026年1月10日由总理阿比·艾哈迈德主持开工。项目投资约125亿美元，规划4条跑道，首期年吞吐6000万人次、终期1.1亿人次，将成为非洲最大机场。航站楼由扎哈·哈迪德建筑事务所设计；埃塞俄比亚航空另投入约3.5亿美元用于移民安置。首期目标2030年建成，并规划高铁连接现有博莱机场与市中心。","descEn":"Africa's largest airport broke ground Jan 2026, ultimate 110M pax/year","detailEn":"Located near Bishoftu, about 45km SE of Addis Ababa, construction was launched on 10 Jan 2026 by PM Abiy Ahmed. The ~$12.5B project features 4 runways, with first-phase capacity of 60M passengers/year rising to 110M, making it Africa's largest airport. The terminal is designed by Zaha Hadid Architects; Ethiopian Airlines is also spending ~$350M on resettlement. Phase-1 completion is targeted for 2030, with a planned high-speed rail link to the existing Bole Airport and the city centre."},
  // ===== 大洋洲（7420-7423）=====
  {"id":7420,"name":"金原野大电池储能(Golden Plains BESS)","en":"Golden Plains Battery Energy Storage System","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[143.85,-37.75],"cap":"150MW/600MWh 储能(168台特斯拉Megapack 2XL)","inv":3,"invText":"约3亿美元(估)","status":"在建","year":2027,"updated":"2026-06","owner":"TagEnergy","flagship":false,"desc":"紧邻南半球最大风电场，四小时时长大电池2026年初开工","detail":"位于澳大利亚维多利亚州吉朗西北约60公里的金原野风电场旁，紧邻在建的1.33GW金原野风电场(南半球最大风电场)。葡萄牙开发商 TagEnergy 于 2025 年 11 月完成融资、2026 年初开工建设该 150MW/600MWh(四小时时长)电池储能系统，采用 168 台特斯拉 Megapack 2XL，为 TagEnergy 在澳的首个储能项目。建设期约两年，计划 2027—2028 年建成投运，为维州电网提供调峰与稳定支撑。","epc":"BoP总包：CPP；电池 Tesla Megapack 2XL(168台)","epcStatus":"已授标","descEn":"Four-hour big battery next to the Southern Hemisphere's largest wind farm, construction started early 2026","detailEn":"About 60 km north-west of Geelong, Victoria, Australia, next to the 1.33 GW Golden Plains Wind Farm (the Southern Hemisphere's largest). Portugal-based developer TagEnergy secured financial close in November 2025 and began construction in early 2026 on the 150MW/600MWh (four-hour) battery, using 168 Tesla Megapack 2XL units and marking its first Australian storage project. Construction takes about two years, with completion targeted for 2027-2028, providing firming and peaking support to the Victorian grid."},
  {"id":7421,"name":"哈利特电池储能一期(Hallett BESS Stage 1)","en":"Hallett Battery Energy Storage System Stage 1","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[138.9,-33.4],"cap":"50MW/250MWh 储能(五小时时长)","inv":1.5,"invText":"约1.5亿美元(估)","status":"在建","year":2027,"updated":"2026-02","owner":"EnergyAustralia / NHOA Energy / Enerven","flagship":false,"desc":"南澳燃气电站旁配套储能，2026年2月融资完成开工","detail":"位于澳大利亚南澳州戈伊德(Goyder)地区，EnergyAustralia 的 50MW/250MWh(五小时时长)哈利特电池储能一期与既有 235MW 燃气电站同址建设，于 2026 年 2 月 13 日达成融资完成并启动交付。项目由 NHOA Energy 担任电池集成商、Enerven 承担土建与电气施工，随后数周内开工，预计 2027 年年中投入商业运营，利用现有并网点为南澳电网提供调峰与稳定支撑。二期(200MW/1000MWh)已获规划批准。","epc":"EPC：NHOA Energy；BoP施工：Enerven","epcStatus":"已授标","descEn":"Storage co-located with a South Australia gas plant, financial close and delivery start February 2026","detailEn":"In the Goyder region of South Australia, EnergyAustralia's 50MW/250MWh (five-hour) Hallett battery Stage 1 is co-located with an existing 235MW gas-fired power station. It reached financial close on 13 February 2026 and moved into delivery, with NHOA Energy as battery integrator and Enerven handling civil and electrical works; construction starts within weeks and commercial operation is expected by mid-2027, using the existing grid connection to firm the SA grid. A Stage 2 (200MW/1,000MWh) already has planning approval."},
  {"id":7422,"name":"格洛里特光伏电站(Glorit Solar Farm)","en":"Glorit Solar Farm","country":"新西兰","region":"大洋洲","cat":"renewable","coord":[174.4,-36.5],"cap":"171MWdc(150MWac)光伏","inv":1.7,"invText":"NZ$2.85亿融资(约1.7亿美元)","status":"在建","year":2028,"updated":"2026-06","owner":"Lightsource bp / Contact Energy","flagship":false,"desc":"新西兰奥克兰以北大型光伏，2026年6月达成2.85亿纽元融资","detail":"位于新西兰奥克兰以北约53公里凯帕拉海岸的格洛里特光伏电站，由 Lightsource bp 与 Contact Energy 合资开发，装机 171MWdc(150MWac)。项目于 2026 年 6 月达成融资完成，获 2.85 亿纽元无追索权融资，贷款方包括澳新银行、瑞穗、中国银行新西兰、中国建设银行新西兰及德国中央合作银行(DZ Bank)。预计 2028 年下半年投入运营，为新西兰电网增添可再生电力，并预留未来储能与调频能力。","descEn":"171MWdc solar farm north of Auckland by Lightsource bp and Contact Energy, NZ$285m financing closed June 2026","detailEn":"On the Kaipara Coast, about 53 km north of Auckland, New Zealand, the Glorit Solar Farm is a 171MWdc (150MWac) joint venture of Lightsource bp and Contact Energy. It reached financial close in June 2026 with NZ$285m of non-recourse financing from ANZ, Mizuho, Bank of China NZ, China Construction Bank NZ and DZ Bank. Operations are expected in the second half of 2028, adding renewable electricity to New Zealand's grid with headroom for future storage and firming."},
  {"id":7423,"name":"陶黑光伏电站(Tauhei Solar Farm)","en":"Tauhei Solar Farm","country":"新西兰","region":"大洋洲","cat":"renewable","coord":[175.62,-37.55],"cap":"202MWp 光伏(占地182公顷)","inv":1.2,"invText":"约1.2亿美元(估)","status":"在建","year":2026,"updated":"2026-06","owner":"Harmony Energy / First Renewables","flagship":false,"desc":"怀卡托Te Aroha附近，新西兰在建最大光伏2026年底投运","detail":"位于新西兰怀卡托 Te Aroha 附近的陶黑光伏电站由 Harmony Energy 新西兰与 First Renewables 合资开发，占地 182 公顷，装机 202MWp，年发电约 280GWh、可满足约 3.5 万户家庭用电。项目于 2025 年 4 月开工、10 月安装首排组件，建设期约两年，高峰期创造约 350 个全职岗位，计划 2026 年底调试并网，届时将成为新西兰规模最大的光伏电站。","descEn":"New Zealand's largest solar farm near Te Aroha, Waikato; commissioning targeted late 2026","detailEn":"Near Te Aroha in the Waikato, New Zealand, the Tauhei Solar Farm is a joint venture of Harmony Energy New Zealand and First Renewables spanning 182 hectares with 202MWp capacity, generating about 280GWh a year, enough for around 35,000 homes. Construction began in April 2025 with the first row of panels installed in October 2025; over a roughly two-year build creating up to 350 jobs at peak, commissioning is expected by late 2026, making it New Zealand's largest solar farm."},
]);
